def _report_is_blocked(report: Optional[Dict[str, object]]) -> bool:
    if not isinstance(report, dict):
        return False
    status = str(report.get("scoring_status") or "").strip().lower()
    if status == "blocked":
        return True
    meta = report.get("meta") if isinstance(report.get("meta"), dict) else {}
    return bool(meta.get("score_blocked_by_material_utilization"))


def _submission_has_generated_score(submission: Dict[str, object]) -> bool:
    report_obj = submission.get("report")
    if isinstance(report_obj, dict):
        status = str(report_obj.get("scoring_status") or "").strip().lower()
        if status == "pending":
            return False
        if _to_float_or_none(report_obj.get("rule_total_score")) is not None:
            return True
        if _to_float_or_none(report_obj.get("pred_total_score")) is not None:
            return True
        if _to_float_or_none(report_obj.get("total_score")) is not None:
            return True
    return _to_float_or_none(submission.get("total_score")) is not None


def _submission_is_scored(submission: Dict[str, object]) -> bool:
    report_obj = submission.get("report")
    if isinstance(report_obj, dict):
        if not _submission_has_generated_score(submission):
            return False
        if _report_is_blocked(report_obj):
            return False
        status = str(report_obj.get("scoring_status") or "").strip().lower()
        if status == "pending":
            return False
        if status == "scored":
            return True
        return True
    return _submission_has_generated_score(submission)


def _mark_report_scored(report: Dict[str, object], *, trigger: str) -> None:
    report["scoring_status"] = "scored"
    report["scoring_trigger"] = trigger
    report["scored_at"] = _now_iso()


def _build_pending_submission_report(
    *,
    project: Dict[str, object],
    scoring_engine_version: str,
) -> Dict[str, object]:
    return {
        "scoring_status": "pending",
        "scoring_trigger": "upload_only",
        "queued_at": _now_iso(),
        "total_score": None,
        "rule_total_score": None,
        "pred_total_score": None,
        "llm_total_score": None,
        "pred_confidence": None,
        "score_blend": None,
        "dimension_scores": {},
        "rule_dim_scores": {},
        "pred_dim_scores": None,
        "penalties": [],
        "lint_findings": [],
        "suggestions": [],
        "requirement_hits": [],
        "mandatory_req_hit_rate": None,
        "evidence_units_count": 0,
        "meta": {
            "engine_version": _determine_engine_version(project, scoring_engine_version),
            "region": project.get("region", DEFAULT_REGION),
            "scoring_engine_version": scoring_engine_version,
            "queued_for_scoring": True,
        },
    }


def _score_submission_for_project(
    *,
    submission_id: str,
    text: str,
    project_id: str,
    project: Dict[str, object],
    config: object,
    multipliers: Dict[str, float],
    profile_snapshot: Optional[Dict[str, object]],
    scoring_engine_version: str,
    anchors: Optional[List[Dict[str, object]]] = None,
    requirements: Optional[List[Dict[str, object]]] = None,
    material_quality_snapshot: Optional[Dict[str, object]] = None,
    material_knowledge_snapshot: Optional[Dict[str, object]] = None,
) -> tuple[Dict[str, object], List[Dict[str, object]]]:
    engine_version = _determine_engine_version(project, scoring_engine_version)
    if engine_version == "v2":
        anchors_from_payload = anchors is not None
        requirements_from_payload = requirements is not None
        anchors = (
            anchors
            if anchors is not None
            else [a for a in load_project_anchors() if str(a.get("project_id")) == project_id]
        )
        requirements = (
            requirements
            if requirements is not None
            else [r for r in load_project_requirements() if str(r.get("project_id")) == project_id]
        )
        constraints_rebuilt = False
        if not anchors or not requirements:
            anchors, requirements = _rebuild_project_anchors_and_requirements(project_id)
            constraints_rebuilt = True
        elif (
            not anchors_from_payload or not requirements_from_payload
        ) and _constraints_need_rebuild(project_id, anchors, requirements):
            anchors, requirements = _rebuild_project_anchors_and_requirements(project_id)
            constraints_rebuilt = True

        weights_norm = (
            dict(profile_snapshot.get("weights_norm") or {})
            if profile_snapshot
            else _weights_from_multipliers(multipliers)
        )
        runtime_custom_requirements, runtime_req_meta = _build_runtime_custom_requirements(
            project_id,
            project=project,
            submission_text=text,
            weights_norm=weights_norm,
        )
        effective_requirements = list(requirements) + list(runtime_custom_requirements)
        meta = project.get("meta") if isinstance(project.get("meta"), dict) else {}
        strict_pre_flight = bool(meta.get("enforce_gb_redline", DEFAULT_ENFORCE_GB_REDLINE))
        try:
            v2_result = score_text_v2(
                submission_id=submission_id,
                text=text,
                lexicon=config.lexicon,
                weights_norm=weights_norm,
                anchors=anchors,
                requirements=effective_requirements,
                strict_pre_flight=strict_pre_flight,
            )
        except ValueError as exc:
            raise HTTPException(status_code=422, detail=str(exc))
        report = _build_v2_report_payload(
            v2_result,
            text=text,
            project=project,
            profile_snapshot=profile_snapshot,
            scoring_engine_version=scoring_engine_version,
        )
        knowledge_snapshot = (
            dict(material_knowledge_snapshot)
            if isinstance(material_knowledge_snapshot, dict)
            else _build_material_knowledge_profile(project_id)
        )
        snapshot_for_meta = (
            dict(material_quality_snapshot)
            if isinstance(material_quality_snapshot, dict)
            else _build_material_quality_snapshot(project_id)
        )
        report_meta = report.get("meta") if isinstance(report.get("meta"), dict) else {}
        report_meta["input_injection"] = _build_scoring_input_injection_meta(
            project_id=project_id,
            text=text,
            anchors_count=len(anchors),
            base_requirements_count=len(requirements),
            runtime_custom_requirements_count=len(runtime_custom_requirements),
            weights_norm=weights_norm,
            profile_snapshot=profile_snapshot,
            constraints_rebuilt=constraints_rebuilt,
            runtime_req_meta=runtime_req_meta,
            material_quality_snapshot=snapshot_for_meta,
        )
        report_meta["material_quality"] = snapshot_for_meta
        report_meta["material_retrieval"] = {
            "chunks": int(
                _to_float_or_none(runtime_req_meta.get("material_retrieval_chunks")) or 0
            ),
            "requirements": int(
                _to_float_or_none(runtime_req_meta.get("material_retrieval_requirements")) or 0
            ),
            "preview": runtime_req_meta.get("material_retrieval_preview") or [],
            "consistency_requirements": int(
                _to_float_or_none(runtime_req_meta.get("material_consistency_requirements")) or 0
            ),
            "consistency_preview": runtime_req_meta.get("material_consistency_preview") or [],
            "available_types": runtime_req_meta.get("material_available_types") or [],
            "retrieval_types": runtime_req_meta.get("material_retrieval_types") or [],
            "missing_types": runtime_req_meta.get("material_retrieval_missing_types") or [],
        }
        report_meta["material_utilization"] = _build_material_utilization_summary(
            report,
            runtime_req_meta,
        )
        gate_obj = snapshot_for_meta.get("gate")
        material_gate_cfg = _resolve_material_gate_config(project)
        material_required_types = (
            material_gate_cfg.get("required_types")
            if isinstance(material_gate_cfg.get("required_types"), list)
            else []
        )
        material_utilization_policy = _resolve_material_utilization_policy(project)
        utilization_gate = _evaluate_material_utilization_gate(
            report_meta.get("material_utilization")
            if isinstance(report_meta.get("material_utilization"), dict)
            else {},
            policy=material_utilization_policy,
            required_types=material_required_types,
        )
        if isinstance(gate_obj, dict):
            report_meta["material_gate"] = gate_obj
        report_meta["material_utilization_gate"] = utilization_gate
        report_meta["material_utilization_alerts"] = _build_material_utilization_alerts(
            report_meta.get("material_utilization")
            if isinstance(report_meta.get("material_utilization"), dict)
            else {},
            gate_obj if isinstance(gate_obj, dict) else {},
        )
        report_meta["evidence_trace"] = _build_evidence_trace_summary(report)
        shaping_meta = _apply_material_constraint_score_shaping(
            report,
            runtime_req_meta=runtime_req_meta,
            material_knowledge_snapshot=knowledge_snapshot,
        )
        report_meta["material_constraint_shaping"] = shaping_meta
        if bool(utilization_gate.get("blocked")):
            report_meta["score_confidence_level"] = "low"
            report_meta["score_blocked_by_material_utilization"] = True
            alerts = (
                report_meta.get("material_utilization_alerts")
                if isinstance(report_meta.get("material_utilization_alerts"), list)
                else []
            )
            for reason in utilization_gate.get("reasons") or []:
                reason_text = str(reason).strip()
                if reason_text and reason_text not in alerts:
                    alerts.append("资料利用门禁：" + reason_text)
            report_meta["material_utilization_alerts"] = alerts[:8]
            report["scoring_status"] = "blocked"
            report["scoring_trigger"] = "material_utilization_gate"
            report["scored_at"] = _now_iso()
        elif bool(utilization_gate.get("warned")):
            report_meta["score_confidence_level"] = "medium"
        else:
            report_meta["score_confidence_level"] = "high"
        report["meta"] = report_meta
        _apply_deployed_patch_to_report(project_id, report)
        submission_like = _build_submission_prediction_context(
            submission_id=submission_id,
            project_id=project_id,
            text=text,
            report=report,
        )
        if _report_is_blocked(report):
            _apply_prediction_to_report(report, submission_like=submission_like, project=project)
            report_meta = report.get("meta") if isinstance(report.get("meta"), dict) else {}
            report_meta = dict(report_meta or {})
            awareness = _build_score_self_awareness(
                report,
                material_knowledge_snapshot=knowledge_snapshot,
            )
            report_meta["score_self_awareness"] = awareness
            report_meta["score_confidence_level"] = str(awareness.get("level") or "low")
            report["meta"] = report_meta
            return report, list(v2_result.get("evidence_units") or [])
        _apply_prediction_to_report(report, submission_like=submission_like, project=project)
        _mark_report_scored(report, trigger="score_engine")
        report_meta = report.get("meta") if isinstance(report.get("meta"), dict) else {}
        report_meta = dict(report_meta or {})
        awareness = _build_score_self_awareness(
            report,
            material_knowledge_snapshot=knowledge_snapshot,
        )
        report_meta["score_self_awareness"] = awareness
        report_meta["score_confidence_level"] = str(
            awareness.get("level") or report_meta.get("score_confidence_level") or "medium"
        )
        report["meta"] = report_meta
        return report, list(v2_result.get("evidence_units") or [])

    legacy = score_text(
        text,
        config.rubric,
        config.lexicon,
        dimension_multipliers=multipliers,
    ).model_dump()
    legacy.setdefault("rule_total_score", float(legacy.get("total_score", 0.0)))
    legacy.setdefault(
        "rule_dim_scores", _rule_dim_scores_from_legacy(legacy.get("dimension_scores", {}))
    )
    legacy.setdefault("pred_dim_scores", None)
    legacy.setdefault("pred_total_score", None)
    legacy.setdefault("pred_confidence", None)
    legacy.setdefault("lint_findings", [])
    legacy.setdefault("requirement_hits", [])
    legacy.setdefault("mandatory_req_hit_rate", None)
    legacy.setdefault("evidence_units_count", 0)
    legacy.setdefault("meta", {})
    legacy["meta"]["engine_version"] = "v1"
    legacy["meta"]["region"] = project.get("region", DEFAULT_REGION)
    legacy["meta"]["scoring_engine_version"] = scoring_engine_version
    if profile_snapshot:
        legacy["meta"]["expert_profile_snapshot"] = profile_snapshot
        legacy["meta"]["expert_profile_id"] = profile_snapshot.get("id")
    legacy["meta"]["evidence_trace"] = _build_evidence_trace_summary(legacy)
    _apply_deployed_patch_to_report(project_id, legacy)
    _mark_report_scored(legacy, trigger="score_engine")
    awareness = _build_score_self_awareness(
        legacy,
        material_knowledge_snapshot=material_knowledge_snapshot,
    )
    legacy["meta"]["score_self_awareness"] = awareness
    legacy["meta"]["score_confidence_level"] = str(awareness.get("level") or "low")
    return legacy, []


def _replace_submission_evidence_units(
    all_units: List[Dict[str, object]],
    *,
    submission_id: str,
    new_units: List[Dict[str, object]],
) -> List[Dict[str, object]]:
    kept = [u for u in all_units if str(u.get("submission_id")) != submission_id]
    kept.extend(new_units)
    return kept


def _latest_records_by_submission(records: List[Dict[str, object]]) -> Dict[str, Dict[str, object]]:
    latest: Dict[str, Dict[str, object]] = {}
    for item in records:
        sid = str(item.get("submission_id") or "")
        if not sid:
            continue
        prev = latest.get(sid)
        if prev is None or str(item.get("created_at", "")) >= str(prev.get("created_at", "")):
            latest[sid] = item
    return latest


def _extract_auto_candidates(model_artifact: Dict[str, Any]) -> List[Dict[str, Any]]:
    best_selection = model_artifact.get("best_selection") or {}
    raw_candidates = best_selection.get("candidates") or []
    if not isinstance(raw_candidates, list):
        return []
    normalized: List[Dict[str, Any]] = []
    for item in raw_candidates:
        if not isinstance(item, dict):
            continue
        metrics = item.get("metrics") or {}
        cv_item = item.get("cv") or {}
        normalized.append(
            {
                "model_type": str(item.get("model_type") or ""),
                "ok": bool(item.get("ok")),
                "gate_passed": bool(item.get("gate_passed")),
                "cv_mae": metrics.get("cv_mae"),
                "cv_rmse": metrics.get("cv_rmse"),
                "cv_spearman": metrics.get("cv_spearman"),
                "cv_mode": cv_item.get("mode"),
                "cv_pred_count": cv_item.get("pred_count"),
            }
        )
    return normalized


def _build_calibrator_summary(
    *,
    model_type: Optional[str],
    calibrator_version: Optional[str],
    gate_passed: Optional[bool],
    cv_metrics: Optional[Dict[str, Any]] = None,
    baseline_metrics: Optional[Dict[str, Any]] = None,
    improve_threshold: Optional[float] = None,
    spearman_tolerance: Optional[float] = None,
    auto_candidates: Optional[List[Dict[str, Any]]] = None,
    sample_count: Optional[int] = None,
    bootstrap_small_sample: bool = False,
    full_validation_min_samples: Optional[int] = LEGACY_PROJECT_LEARNING_MIN_SAMPLES,
    deployment_mode: Optional[str] = None,
    auto_review: Optional[Dict[str, Any]] = None,
    skipped_reason: Optional[str] = None,
) -> Dict[str, Any]:
    gate_payload: Dict[str, Any] = {}
    if gate_passed is not None:
        gate_payload["passed"] = bool(gate_passed)
    if improve_threshold is not None:
        gate_payload["improve_threshold"] = round(float(improve_threshold), 4)
    if spearman_tolerance is not None:
        gate_payload["spearman_tolerance"] = float(spearman_tolerance)

    summary: Dict[str, Any] = {
        "calibrator_version": calibrator_version,
        "model_type": model_type,
        "gate_passed": gate_passed,
        "cv_metrics": cv_metrics or {},
        "baseline_metrics": baseline_metrics or {},
        "gate": gate_payload,
        "auto_candidates": auto_candidates or [],
        "bootstrap_small_sample": bool(bootstrap_small_sample),
        "full_validation_min_samples": (
            int(full_validation_min_samples) if full_validation_min_samples is not None else None
        ),
        "deployment_mode": deployment_mode,
        "auto_review": auto_review or {},
    }
    if sample_count is not None:
        summary["sample_count"] = int(sample_count)
    if skipped_reason:
        summary["skipped_reason"] = skipped_reason
    return summary


def _normalize_calibrator_auto_review_state(payload: object) -> Dict[str, Any]:
    data = payload if isinstance(payload, dict) else {}
    passed_raw = data.get("passed")
    passed = passed_raw if isinstance(passed_raw, bool) else None
    return {
        "checked": bool(data.get("checked")),
        "passed": passed,
        "action": str(data.get("action") or "skip").strip().lower() or "skip",
        "reason": str(data.get("reason") or "not_run").strip() or "not_run",
        "review_mode": str(data.get("review_mode") or "bootstrap_preview").strip()
        or "bootstrap_preview",
        "reviewed_at": str(data.get("reviewed_at") or ""),
        "matched_submission_count": int(
            _to_float_or_none(data.get("matched_submission_count")) or 0
        ),
        "avg_abs_delta_stored": _to_float_or_none(data.get("avg_abs_delta_stored")),
        "avg_abs_delta_preview": _to_float_or_none(data.get("avg_abs_delta_preview")),
        "avg_abs_delta_improvement": _to_float_or_none(data.get("avg_abs_delta_improvement")),
        "improved_row_count": int(_to_float_or_none(data.get("improved_row_count")) or 0),
        "worsened_row_count": int(_to_float_or_none(data.get("worsened_row_count")) or 0),
        "max_allowed_avg_delta_increase": float(
            _to_float_or_none(data.get("max_allowed_avg_delta_increase"))
            or DEFAULT_BOOTSTRAP_CALIBRATION_MAX_AVG_DELTA_INCREASE
        ),
    }


def _calibrator_summary_dict(model: Dict[str, object]) -> Dict[str, object]:
    return (
        model.get("calibrator_summary") if isinstance(model.get("calibrator_summary"), dict) else {}
    )


def _calibrator_bootstrap_small_sample(model: Dict[str, object]) -> bool:
    summary = _calibrator_summary_dict(model)
    if "bootstrap_small_sample" in summary:
        return bool(summary.get("bootstrap_small_sample"))
    metrics = model.get("metrics") if isinstance(model.get("metrics"), dict) else {}
    return bool(metrics.get("bootstrap_small_sample"))


def _calibrator_deployment_mode(model: Dict[str, object]) -> str:
    summary = _calibrator_summary_dict(model)
    mode = str(summary.get("deployment_mode") or "").strip()
    if mode:
        return mode
    version = str(model.get("calibrator_version") or "").strip()
    if version.startswith("prior_"):
        return "prior_fallback"
    if bool(model.get("deployed")):
        return (
            "bootstrap_auto_deploy" if _calibrator_bootstrap_small_sample(model) else "cv_validated"
        )
    if bool(model.get("gate_passed")) is False:
        return "gate_rejected"
    return "candidate_only"


def _calibrator_auto_review_state(model: Dict[str, object]) -> Dict[str, Any]:
    summary = _calibrator_summary_dict(model)
    return _normalize_calibrator_auto_review_state(summary.get("auto_review"))


def _calibrator_train_scope_project_id(model: Dict[str, object]) -> str:
    return str(((model.get("train_filter") or {}).get("project_id") or "")).strip()


def _calibrator_gate_passed(model: Dict[str, object]) -> Optional[bool]:
    summary = _calibrator_summary_dict(model)
    if "gate_passed" in summary:
        return bool(summary.get("gate_passed"))
    metrics = model.get("metrics") if isinstance(model.get("metrics"), dict) else {}
    if "gate_passed" in metrics:
        return bool(metrics.get("gate_passed"))
    raw = model.get("gate_passed")
    if raw is None:
        return None
    return bool(raw)


def _calibrator_cv_mae(model: Dict[str, object]) -> Optional[float]:
    summary = _calibrator_summary_dict(model)
    cv_metrics = summary.get("cv_metrics") if isinstance(summary.get("cv_metrics"), dict) else {}
    value = _to_float_or_none(cv_metrics.get("mae"))
    if value is not None:
        return float(value)
    metrics = model.get("metrics") if isinstance(model.get("metrics"), dict) else {}
    return _to_float_or_none(metrics.get("cv_mae") or metrics.get("mae"))


def _current_project_calibrator_record(
    project: Dict[str, object],
    rows: List[Dict[str, object]],
) -> Optional[Dict[str, object]]:
    current = _select_calibrator_model_from_rows(project, rows or [])
    if not isinstance(current, dict):
        return None
    if not _calibrator_train_scope_project_id(current):
        return None
    if str(current.get("calibrator_version") or "").strip().startswith("prior_"):
        return None
    return current


def _find_project_calibrator_rollback_candidate(
    project: Dict[str, object],
    rows: List[Dict[str, object]],
) -> Optional[Dict[str, object]]:
    current = _current_project_calibrator_record(project, rows or [])
    if not isinstance(current, dict):
        return None
    project_id = str(project.get("id") or "").strip()
    current_version = str(current.get("calibrator_version") or "").strip()
    current_cv_mae = _calibrator_cv_mae(current)
    candidates: List[Dict[str, object]] = []
    for row in rows or []:
        if not isinstance(row, dict):
            continue
        if _calibrator_train_scope_project_id(row) != project_id:
            continue
        version = str(row.get("calibrator_version") or "").strip()
        if not version or version == current_version or version.startswith("prior_"):
            continue
        deployment_mode = _calibrator_deployment_mode(row)
        if deployment_mode not in {"cv_validated", "bootstrap_auto_deploy"}:
            continue
        gate_passed = _calibrator_gate_passed(row)
        # Older historical rows can lose `deployed=True` after a newer model is promoted,
        # while still retaining a deployed-mode summary but no explicit gate flag.
        if gate_passed is False:
            continue
        if gate_passed is None and deployment_mode not in {"cv_validated", "bootstrap_auto_deploy"}:
            continue
        candidate_cv_mae = _calibrator_cv_mae(row)
        if (
            current_cv_mae is not None
            and candidate_cv_mae is not None
            and candidate_cv_mae
            > current_cv_mae - float(DEFAULT_PROJECT_CALIBRATOR_PROMOTION_MIN_MAE_IMPROVEMENT)
        ):
            continue
        candidates.append(row)
    if not candidates:
        return None

    def _candidate_priority(row: Dict[str, object]) -> tuple[int, float, str]:
        mode = _calibrator_deployment_mode(row)
        mode_priority = 0 if mode == "cv_validated" else 1
        cv_mae = _calibrator_cv_mae(row)
        return (
            mode_priority,
            float(cv_mae) if cv_mae is not None else 9999.0,
            str(row.get("updated_at") or row.get("created_at") or ""),
        )

    return sorted(candidates, key=_candidate_priority)[0]


def _auto_recover_degraded_project_calibrator(
    *,
    project_id: str,
    project: Dict[str, object],
    locale: str,
) -> Dict[str, Any]:
    result: Dict[str, Any] = {
        "checked": False,
        "degraded_before": False,
        "degraded_after": None,
        "recovered_after": None,
        "action": "skip",
        "reason": "not_checked",
        "rollback_candidate_version": None,
        "matched_submission_count": 0,
        "avg_abs_delta_stored": None,
        "avg_abs_delta_preview": None,
        "avg_abs_delta_improvement": None,
        "mae_after": None,
        "rule_mae_after": None,
        "mae_delta_vs_rule_after": None,
        "updated_reports": 0,
        "updated_submissions": 0,
        "active_calibrator_version_after": None,
    }
    health = _build_evolution_health_report(project_id, project)
    summary = health.get("summary") if isinstance(health, dict) else {}
    if not isinstance(summary, dict):
        return result
    result["checked"] = True
    result["degraded_before"] = bool(summary.get("current_calibrator_degraded"))
    result["active_calibrator_version_after"] = summary.get("current_calibrator_version")
    rollback_version = str(
        summary.get("current_calibrator_rollback_candidate_version") or ""
    ).strip()
    result["rollback_candidate_version"] = rollback_version or None
    if not bool(summary.get("current_calibrator_degraded")):
        result["reason"] = "current_calibrator_healthy"
        return result
    if not rollback_version:
        result["reason"] = "no_rollback_candidate"
        return result

    models = load_calibration_models()
    candidate = next(
        (
            row
            for row in models
            if str(row.get("calibrator_version") or "").strip() == rollback_version
        ),
        None,
    )
    if not isinstance(candidate, dict):
        result["reason"] = "rollback_candidate_missing"
        return result

    override_rows = _build_calibration_models_preview_override(project, models, candidate)
    preview_project = dict(project)
    preview_project["calibrator_version_locked"] = rollback_version
    preview = _build_governance_score_preview(
        project_id,
        preview_project,
        [],
        artifact_payload_overrides={"calibration_models": override_rows},
    )
    matched_submission_count = int(_to_float_or_none(preview.get("matched_submission_count")) or 0)
    avg_abs_delta_stored = _to_float_or_none(preview.get("avg_abs_delta_stored"))
    avg_abs_delta_preview = _to_float_or_none(preview.get("avg_abs_delta_preview"))
    avg_abs_delta_improvement = _to_float_or_none(preview.get("avg_abs_delta_improvement"))
    result.update(
        {
            "matched_submission_count": matched_submission_count,
            "avg_abs_delta_stored": avg_abs_delta_stored,
            "avg_abs_delta_preview": avg_abs_delta_preview,
            "avg_abs_delta_improvement": avg_abs_delta_improvement,
        }
    )
    if (
        matched_submission_count <= 0
        or avg_abs_delta_stored is None
        or avg_abs_delta_preview is None
    ):
        result["reason"] = "no_comparable_rows"
        return result

    tolerance = float(DEFAULT_BOOTSTRAP_CALIBRATION_MAX_AVG_DELTA_INCREASE)
    if float(avg_abs_delta_preview) > float(avg_abs_delta_stored) + tolerance:
        result["reason"] = "rollback_preview_worsened_beyond_tolerance"
        return result
    if float(avg_abs_delta_preview) >= float(avg_abs_delta_stored) - 0.01:
        result["reason"] = "rollback_preview_not_improved"
        return result

    deploy_calibrator(
        CalibratorDeployRequest(
            calibrator_version=rollback_version,
            project_id=project_id,
        ),
        api_key=None,
    )
    prediction_result = apply_calibration_prediction(
        project_id,
        api_key=None,
        locale=locale,
    )
    result["action"] = "rollback"
    result["reason"] = "rollback_preview_improved"
    result["updated_reports"] = int(prediction_result.updated_reports or 0)
    result["updated_submissions"] = int(prediction_result.updated_submissions or 0)
    refreshed_projects = load_projects()
    refreshed_project = next(
        (row for row in refreshed_projects if str(row.get("id") or "").strip() == project_id),
        None,
    )
    verify_health = _build_evolution_health_report(project_id, refreshed_project or project)
    verify_summary = verify_health.get("summary") if isinstance(verify_health, dict) else {}
    if isinstance(verify_summary, dict):
        degraded_after = bool(verify_summary.get("current_calibrator_degraded"))
        result["degraded_after"] = degraded_after
        result["recovered_after"] = not degraded_after
        result["mae_after"] = _to_float_or_none(verify_summary.get("current_calibrator_recent_mae"))
        result["rule_mae_after"] = _to_float_or_none(
            verify_summary.get("current_calibrator_recent_rule_mae")
        )
        result["mae_delta_vs_rule_after"] = _to_float_or_none(
            verify_summary.get("current_calibrator_recent_mae_delta_vs_rule")
        )
        result["active_calibrator_version_after"] = (
            str(verify_summary.get("current_calibrator_version") or "").strip() or rollback_version
        )
    else:
        result["active_calibrator_version_after"] = rollback_version
    return result


def _should_keep_existing_project_calibrator(
    *,
    project: Dict[str, object],
    existing_models: List[Dict[str, object]],
    candidate_record: Dict[str, object],
) -> bool:
    current = _current_project_calibrator_record(project, existing_models)
    if current is None:
        return False
    project_id = str(project.get("id") or "").strip()
    if not project_id:
        return False
    if _calibrator_train_scope_project_id(current) != project_id:
        return False

    current_gate_passed = _calibrator_gate_passed(current)
    candidate_gate_passed = _calibrator_gate_passed(candidate_record)
    if current_gate_passed is not True or candidate_gate_passed is not True:
        return False

    current_mode = _calibrator_deployment_mode(current)
    candidate_mode = _calibrator_deployment_mode(candidate_record)
    if current_mode == "cv_validated" and candidate_mode != "cv_validated":
        return True

    current_cv_mae = _calibrator_cv_mae(current)
    candidate_cv_mae = _calibrator_cv_mae(candidate_record)
    if current_cv_mae is not None and candidate_cv_mae is None:
        return True
    if current_cv_mae is None or candidate_cv_mae is None:
        return False
    return candidate_cv_mae > (
        current_cv_mae - float(DEFAULT_PROJECT_CALIBRATOR_PROMOTION_MIN_MAE_IMPROVEMENT)
    )


def _project_calibrator_rows(
    project: Dict[str, object],
    rows: List[Dict[str, object]],
) -> List[Dict[str, object]]:
    project_id = str(project.get("id") or "").strip()
    return sorted(
        [
            row
            for row in rows
            if str(((row.get("train_filter") or {}).get("project_id") or "")).strip() == project_id
        ],
        key=lambda row: str(row.get("updated_at") or row.get("created_at") or ""),
        reverse=True,
    )


def _summarize_project_calibrator_state(
    project: Dict[str, object],
    rows: List[Dict[str, object]],
) -> Dict[str, object]:
    current = _select_calibrator_model_from_rows(project, rows or []) or {}
    project_rows = _project_calibrator_rows(project, rows or [])
    latest_project = project_rows[0] if project_rows else {}
    current_version = str(current.get("calibrator_version") or "").strip()
    latest_project_version = str(latest_project.get("calibrator_version") or "").strip()
    current_source = "none"
    if current_version:
        current_source = "prior" if current_version.startswith("prior_") else "project"
    return {
        "current_calibrator_version": current_version or None,
        "current_calibrator_model_type": str(current.get("model_type") or "") or None,
        "current_calibrator_source": current_source,
        "current_calibrator_bootstrap_small_sample": _calibrator_bootstrap_small_sample(current),
        "current_calibrator_deployment_mode": _calibrator_deployment_mode(current),
        "current_calibrator_auto_review": _calibrator_auto_review_state(current),
        "latest_project_calibrator_version": latest_project_version or None,
        "latest_project_calibrator_model_type": str(latest_project.get("model_type") or "") or None,
        "latest_project_calibrator_deployed": bool(latest_project.get("deployed")),
        "latest_project_calibrator_bootstrap_small_sample": _calibrator_bootstrap_small_sample(
            latest_project
        ),
        "latest_project_calibrator_deployment_mode": _calibrator_deployment_mode(latest_project),
        "latest_project_calibrator_auto_review": _calibrator_auto_review_state(latest_project),
    }


def _build_calibration_models_preview_override(
    project: Dict[str, object],
    existing_rows: List[Dict[str, object]],
    candidate_record: Dict[str, object],
) -> List[Dict[str, object]]:
    project_id = str(project.get("id") or "").strip()
    candidate_version = str(candidate_record.get("calibrator_version") or "").strip()
    preview_rows: List[Dict[str, object]] = []
    for row in existing_rows:
        copied = copy.deepcopy(row) if isinstance(row, dict) else {}
        if (
            project_id
            and str(((copied.get("train_filter") or {}).get("project_id") or "")).strip()
            == project_id
        ):
            copied["deployed"] = False
        preview_rows.append(copied)
    candidate_copy = copy.deepcopy(candidate_record)
    candidate_copy["deployed"] = True
    if candidate_version:
        preview_rows = [
            row
            for row in preview_rows
            if str(row.get("calibrator_version") or "").strip() != candidate_version
        ]
    preview_rows.append(candidate_copy)
    return preview_rows


def _build_calibrator_auto_review(
    *,
    project_id: str,
    project: Dict[str, object],
    existing_models: List[Dict[str, object]],
    candidate_record: Dict[str, object],
) -> Dict[str, Any]:
    bootstrap_small_sample = _calibrator_bootstrap_small_sample(candidate_record)
    default_action = "keep_with_monitoring" if bootstrap_small_sample else "keep"
    review_mode = "bootstrap_preview" if bootstrap_small_sample else "deployment_preview"
    result: Dict[str, Any] = {
        "checked": False,
        "passed": None,
        "action": default_action,
        "reason": "not_required",
        "review_mode": review_mode,
        "reviewed_at": _now_iso(),
        "matched_submission_count": 0,
        "avg_abs_delta_stored": None,
        "avg_abs_delta_preview": None,
        "avg_abs_delta_improvement": None,
        "improved_row_count": 0,
        "worsened_row_count": 0,
        "max_allowed_avg_delta_increase": DEFAULT_BOOTSTRAP_CALIBRATION_MAX_AVG_DELTA_INCREASE,
    }
    if not bool(candidate_record.get("deployed")):
        result["action"] = "skip"
        result["reason"] = "candidate_not_deployed"
        return result

    override_rows = _build_calibration_models_preview_override(
        project, existing_models, candidate_record
    )
    artifact_payload_overrides = {"calibration_models": override_rows}
    artifact_impacts = _build_governance_artifact_impacts(
        project_id,
        artifact_payload_overrides=artifact_payload_overrides,
    )
    preview = _build_governance_score_preview(
        project_id,
        project,
        artifact_impacts,
        artifact_payload_overrides=artifact_payload_overrides,
    )
    matched_submission_count = int(_to_float_or_none(preview.get("matched_submission_count")) or 0)
    avg_abs_delta_stored = _to_float_or_none(preview.get("avg_abs_delta_stored"))
    avg_abs_delta_preview = _to_float_or_none(preview.get("avg_abs_delta_preview"))
    avg_abs_delta_improvement = _to_float_or_none(preview.get("avg_abs_delta_improvement"))
    improved_row_count = int(_to_float_or_none(preview.get("improved_row_count")) or 0)
    worsened_row_count = int(_to_float_or_none(preview.get("worsened_row_count")) or 0)
    result.update(
        {
            "matched_submission_count": matched_submission_count,
            "avg_abs_delta_stored": avg_abs_delta_stored,
            "avg_abs_delta_preview": avg_abs_delta_preview,
            "avg_abs_delta_improvement": avg_abs_delta_improvement,
            "improved_row_count": improved_row_count,
            "worsened_row_count": worsened_row_count,
        }
    )
    if (
        matched_submission_count <= 0
        or avg_abs_delta_stored is None
        or avg_abs_delta_preview is None
    ):
        result["action"] = default_action
        result["reason"] = "no_comparable_rows"
        return result

    result["checked"] = True
    tolerance = float(result["max_allowed_avg_delta_increase"])
    preview_worsened = float(avg_abs_delta_preview) > float(avg_abs_delta_stored) + tolerance
    if preview_worsened:
        result["passed"] = False
        result["action"] = "rollback"
        result["reason"] = "preview_worsened_beyond_tolerance"
    elif float(avg_abs_delta_preview) + 1e-6 < float(avg_abs_delta_stored):
        result["passed"] = True
        result["action"] = "keep"
        result["reason"] = "preview_improved"
    else:
        result["passed"] = True
        result["action"] = default_action
        result["reason"] = "preview_non_inferior_within_tolerance"
    return result


def _finalize_calibrator_record_for_deploy(
    *,
    project: Optional[Dict[str, object]],
    existing_models: List[Dict[str, object]],
    record: Dict[str, object],
    auto_deploy_requested: bool,
) -> Dict[str, Any]:
    summary = dict(record.get("calibrator_summary") or {})
    metrics = dict(record.get("metrics") or {})
    bootstrap_small_sample = _calibrator_bootstrap_small_sample(record)
    auto_review = _normalize_calibrator_auto_review_state(summary.get("auto_review"))
    deployment_mode = "candidate_only"
    if not bool(record.get("gate_passed")) and not bool(metrics.get("gate_passed")):
        deployment_mode = "gate_rejected"
    elif bool(record.get("deployed")):
        deployment_mode = "bootstrap_auto_deploy" if bootstrap_small_sample else "cv_validated"
    elif bootstrap_small_sample:
        deployment_mode = "bootstrap_candidate_only"

    if (
        auto_deploy_requested
        and bool(record.get("deployed"))
        and isinstance(project, dict)
        and str(project.get("id") or "").strip()
    ):
        if _should_keep_existing_project_calibrator(
            project=project,
            existing_models=existing_models,
            candidate_record=record,
        ):
            auto_review = _normalize_calibrator_auto_review_state(
                {
                    "checked": True,
                    "passed": True,
                    "action": "keep_existing",
                    "reason": "existing_better_project_calibrator_kept",
                    "review_mode": "deployment_guard",
                    "reviewed_at": _now_iso(),
                }
            )
            record["deployed"] = False
            deployment_mode = (
                "bootstrap_candidate_only" if bootstrap_small_sample else "candidate_only"
            )
        else:
            auto_review = _build_calibrator_auto_review(
                project_id=str(project.get("id") or ""),
                project=project,
                existing_models=existing_models,
                candidate_record=record,
            )
            if (
                bool(auto_review.get("checked"))
                and str(auto_review.get("action") or "") == "rollback"
            ):
                record["deployed"] = False
                deployment_mode = (
                    "bootstrap_candidate_only" if bootstrap_small_sample else "candidate_only"
                )
            elif (
                bootstrap_small_sample
                and str(auto_review.get("action") or "") == "keep_with_monitoring"
            ):
                deployment_mode = "bootstrap_auto_deploy"

    summary["bootstrap_small_sample"] = bool(bootstrap_small_sample)
    summary["full_validation_min_samples"] = LEGACY_PROJECT_LEARNING_MIN_SAMPLES
    summary["deployment_mode"] = deployment_mode
    summary["auto_review"] = auto_review
    record["calibrator_summary"] = summary
    metrics["bootstrap_small_sample"] = bool(bootstrap_small_sample)
    metrics["deployment_mode"] = deployment_mode
    metrics["auto_review_checked"] = bool(auto_review.get("checked"))
    metrics["auto_review_passed"] = auto_review.get("passed")
    metrics["auto_review_action"] = auto_review.get("action")
    metrics["auto_review_reason"] = auto_review.get("reason")
    metrics["auto_review_matched_submission_count"] = int(
        _to_float_or_none(auto_review.get("matched_submission_count")) or 0
    )
    metrics["auto_review_avg_abs_delta_stored"] = _to_float_or_none(
        auto_review.get("avg_abs_delta_stored")
    )
    metrics["auto_review_avg_abs_delta_preview"] = _to_float_or_none(
        auto_review.get("avg_abs_delta_preview")
    )
    metrics["auto_review_avg_abs_delta_improvement"] = _to_float_or_none(
        auto_review.get("avg_abs_delta_improvement")
    )
    record["metrics"] = metrics
    return record


def _build_calibration_baseline_metrics(
    feature_rows: List[Dict[str, Any]],
) -> Dict[str, Any]:
    labeled_rows = [row for row in feature_rows if row.get("y_label") is not None]
    y_true = [float(row.get("y_label")) for row in labeled_rows]
    baseline_pred = [
        max(0.0, min(100.0, float(((row.get("x_features") or {}).get("rule_total_score") or 0.0))))
        for row in labeled_rows
    ]
    return calc_metrics(y_true, baseline_pred)


def _compute_calibration_label_score_span(
    feature_rows: List[Dict[str, Any]],
) -> float:
    labeled_rows = [row for row in feature_rows if row.get("y_label") is not None]
    y_true = [float(row.get("y_label")) for row in labeled_rows]
    if len(y_true) < 2:
        return 0.0
    return round(max(y_true) - min(y_true), 4)


def _should_allow_clustered_score_gate_override(
    *,
    feature_rows: List[Dict[str, Any]],
    baseline_metrics: Dict[str, Any],
    cv_metrics: Dict[str, Any],
    sample_count: int,
    improve_threshold: float,
) -> bool:
    baseline_mae = float(baseline_metrics.get("mae") or 0.0)
    cv_mae = float(cv_metrics.get("mae") or 0.0)
    label_score_span = _compute_calibration_label_score_span(feature_rows)
    if sample_count < 5:
        return False
    if label_score_span > 6.0:
        return False
    if baseline_mae < 10.0:
        return False
    if cv_mae > baseline_mae - float(improve_threshold):
        return False
    if cv_mae > min(3.0, baseline_mae * 0.08):
        return False
    return True


def _train_calibrator_with_gate(
    feature_rows: List[Dict[str, Any]],
    *,
    model_type: str,
    alpha: float,
    sample_floor: int,
    seed: int = 42,
) -> Dict[str, Any]:
    labeled_rows = [row for row in feature_rows if row.get("y_label") is not None]
    sample_count = len(labeled_rows)
    if sample_count < max(1, int(sample_floor)):
        raise ValueError(f"训练样本不足，至少需要{max(1, int(sample_floor))}条可用样本")

    requested_model_type = str(model_type or "auto").lower().strip()
    baseline_metrics = _build_calibration_baseline_metrics(labeled_rows)
    improve_threshold = max(0.2, float(baseline_metrics.get("mae") or 0.0) * 0.01)
    spearman_tolerance = 0.02
    bootstrap_small_sample = sample_count < LEGACY_PROJECT_LEARNING_MIN_SAMPLES

    if bootstrap_small_sample:
        if requested_model_type not in {"auto", "offset"}:
            raise ValueError(
                "小样本模式仅支持 auto/offset；至少需要3条可用样本才能训练 "
                "linear1d/isotonic1d/ridge"
            )
        model_artifact = train_offset_calibrator(labeled_rows)
        selected_type = "offset"
        cv = {
            "ok": True,
            "metrics": {
                "mae": float(((model_artifact.get("metrics") or {}).get("mae") or 0.0)),
                "rmse": float(((model_artifact.get("metrics") or {}).get("rmse") or 0.0)),
                "spearman": float(((model_artifact.get("metrics") or {}).get("spearman") or 0.0)),
            },
            "pred_count": sample_count,
            "mode": "bootstrap_in_sample",
        }
        gate_passed = bool(model_artifact.get("gate_passed"))
    else:
        if requested_model_type == "auto":
            model_artifact = train_best_calibrator_auto(labeled_rows, alpha=float(alpha), seed=seed)
        elif requested_model_type == "offset":
            model_artifact = train_offset_calibrator(labeled_rows)
        elif requested_model_type == "linear1d":
            model_artifact = train_linear1d_calibrator(labeled_rows, alpha=float(alpha))
        elif requested_model_type == "isotonic1d":
            model_artifact = train_isotonic1d_calibrator(labeled_rows)
        else:
            model_artifact = train_ridge_calibrator(labeled_rows, alpha=float(alpha))
        selected_type = str(model_artifact.get("model_type") or requested_model_type or "ridge")
        cv = cross_validate_calibrator(
            model_type=selected_type,
            feature_rows=labeled_rows,
            alpha=float(alpha),
            seed=seed,
        )
        cv_metrics = (
            (cv.get("metrics") or {})
            if bool(cv.get("ok"))
            else {"mae": 0.0, "rmse": 0.0, "spearman": 0.0}
        )
        gate_passed = (
            bool(cv.get("ok"))
            and float(cv_metrics.get("mae") or 0.0)
            <= float(baseline_metrics.get("mae") or 0.0) - improve_threshold
            and float(cv_metrics.get("spearman") or 0.0)
            >= float(baseline_metrics.get("spearman") or 0.0) - spearman_tolerance
        )
        clustered_score_override = bool(
            cv.get("ok")
        ) and _should_allow_clustered_score_gate_override(
            feature_rows=labeled_rows,
            baseline_metrics=baseline_metrics,
            cv_metrics=cv_metrics,
            sample_count=sample_count,
            improve_threshold=improve_threshold,
        )
        gate_passed = gate_passed or clustered_score_override
    label_score_span = _compute_calibration_label_score_span(labeled_rows)
    clustered_score_override = bool(locals().get("clustered_score_override", False))

    cv_metrics = (
        (cv.get("metrics") or {})
        if bool(cv.get("ok"))
        else {"mae": 0.0, "rmse": 0.0, "spearman": 0.0}
    )
    model_artifact.setdefault("metrics", {})
    model_artifact["metrics"]["cv_mae"] = cv_metrics.get("mae")
    model_artifact["metrics"]["cv_rmse"] = cv_metrics.get("rmse")
    model_artifact["metrics"]["cv_spearman"] = cv_metrics.get("spearman")
    model_artifact["metrics"]["cv_mode"] = cv.get("mode")
    model_artifact["metrics"]["cv_pred_count"] = cv.get("pred_count")
    model_artifact["metrics"]["baseline_mae"] = baseline_metrics.get("mae")
    model_artifact["metrics"]["baseline_rmse"] = baseline_metrics.get("rmse")
    model_artifact["metrics"]["baseline_spearman"] = baseline_metrics.get("spearman")
    model_artifact["metrics"]["label_score_span"] = label_score_span
    model_artifact["metrics"]["gate_improve_threshold"] = round(improve_threshold, 4)
    model_artifact["metrics"]["gate_spearman_tolerance"] = spearman_tolerance
    model_artifact["metrics"]["gate_clustered_score_override"] = bool(clustered_score_override)
    if bootstrap_small_sample:
        model_artifact["metrics"]["bootstrap_small_sample"] = True
        model_artifact["metrics"]["bootstrap_sample_count"] = sample_count
    model_artifact["gate_passed"] = bool(gate_passed)

    auto_candidates = _extract_auto_candidates(model_artifact)
    if bootstrap_small_sample and not auto_candidates:
        auto_candidates = [
            {
                "model_type": selected_type,
                "ok": True,
                "gate_passed": bool(gate_passed),
                "metrics": dict(model_artifact.get("metrics") or {}),
            }
        ]
    summary = _build_calibrator_summary(
        model_type=selected_type,
        calibrator_version=None,
        gate_passed=bool(gate_passed),
        cv_metrics={
            "mae": cv_metrics.get("mae"),
            "rmse": cv_metrics.get("rmse"),
            "spearman": cv_metrics.get("spearman"),
            "mode": cv.get("mode"),
            "pred_count": cv.get("pred_count"),
        },
        baseline_metrics={
            "mae": baseline_metrics.get("mae"),
            "rmse": baseline_metrics.get("rmse"),
            "spearman": baseline_metrics.get("spearman"),
        },
        improve_threshold=improve_threshold,
        spearman_tolerance=spearman_tolerance,
        auto_candidates=auto_candidates,
        sample_count=sample_count,
        bootstrap_small_sample=bootstrap_small_sample,
        full_validation_min_samples=LEGACY_PROJECT_LEARNING_MIN_SAMPLES,
        deployment_mode="candidate_only",
        auto_review=_normalize_calibrator_auto_review_state({}),
    )
    gate_payload = summary.get("gate") if isinstance(summary.get("gate"), dict) else {}
    gate_payload["label_score_span"] = label_score_span
    gate_payload["clustered_score_override"] = bool(clustered_score_override)
    summary["gate"] = gate_payload
    return {
        "model_artifact": model_artifact,
        "selected_type": selected_type,
        "gate_passed": bool(gate_passed),
        "cv": cv,
        "cv_metrics": summary.get("cv_metrics") or {},
        "baseline_metrics": summary.get("baseline_metrics") or {},
        "gate": summary.get("gate") or {},
        "auto_candidates": auto_candidates,
        "summary": summary,
        "sample_count": sample_count,
        "bootstrap_small_sample": bootstrap_small_sample,
    }


def _refresh_project_reflection_objects(
    project_id: str,
    *,
    include_guardrail_blocked: bool = False,
) -> None:
    submissions = [s for s in load_submissions() if str(s.get("project_id")) == project_id]
    submissions_by_id = {str(s.get("id")): s for s in submissions}
    latest_reports = _latest_records_by_submission(
        [r for r in load_score_reports() if str(r.get("project_id")) == project_id]
    )
    projects = load_projects()
    project = next((p for p in projects if str(p.get("id")) == project_id), {})
    project_score_scale = _resolve_project_score_scale_max(project) if project else 100
    training_blocked_gt_ids = {
        str(row.get("id") or "").strip()
        for row in _list_project_ground_truth_records(
            project_id,
            include_guardrail_blocked=True,
        )
        if _feedback_guardrail_blocks_training(row)
    }
    learning_quality_blocked_gt_ids = {
        str(row.get("id") or "").strip()
        for row in _list_project_ground_truth_records(
            project_id,
            include_guardrail_blocked=True,
        )
        if _learning_quality_gate_is_blocked(row)
    }

    qingtian_results = load_qingtian_results()
    qingtian_changed = False
    scoped_qt: List[Dict[str, object]] = []
    for q in qingtian_results:
        sid = str(q.get("submission_id") or "")
        if sid not in submissions_by_id:
            continue
        raw_payload = q.get("raw_payload") if isinstance(q.get("raw_payload"), dict) else {}
        normalized_record = _ground_truth_record_for_learning(
            {
                "final_score": raw_payload.get("final_score"),
                "final_score_raw": raw_payload.get("final_score_raw"),
                "final_score_100": raw_payload.get("final_score_100"),
                "score_scale_max": raw_payload.get("score_scale_max"),
                "judge_scores": raw_payload.get("judge_scores") or [],
            },
            default_score_scale_max=project_score_scale,
        )
        normalized_qt_score = float(normalized_record.get("final_score", 0.0))
        old_qt_score = _to_float_or_none(q.get("qt_total_score"))
        if old_qt_score is None or abs(old_qt_score - normalized_qt_score) > 1e-6:
            q["qt_total_score"] = normalized_qt_score
            qingtian_changed = True
        merged_payload = dict(raw_payload or {})
        merged_payload["final_score_raw"] = normalized_record.get("final_score_raw")
        merged_payload["final_score_100"] = normalized_qt_score
        merged_payload["score_scale_max"] = normalized_record.get("score_scale_max")
        if merged_payload != raw_payload:
            q["raw_payload"] = merged_payload
            qingtian_changed = True
        gt_record_id = str(merged_payload.get("ground_truth_record_id") or "").strip()
        if gt_record_id and gt_record_id in learning_quality_blocked_gt_ids:
            continue
        if (
            not include_guardrail_blocked
            and gt_record_id
            and gt_record_id in training_blocked_gt_ids
        ):
            continue
        scoped_qt.append(q)
    if qingtian_changed:
        save_qingtian_results(qingtian_results)

    latest_qt = _latest_records_by_submission(scoped_qt)

    delta_cases = build_delta_cases(
        project_id=project_id,
        latest_reports_by_submission=latest_reports,
        latest_qingtian_by_submission=latest_qt,
    )
    all_delta = [d for d in load_delta_cases() if str(d.get("project_id")) != project_id]
    all_delta.extend(delta_cases)
    save_delta_cases(all_delta)

    samples = build_calibration_samples(
        project_id=project_id,
        latest_reports_by_submission=latest_reports,
        latest_qingtian_by_submission=latest_qt,
        submissions_by_id=submissions_by_id,
    )
    all_samples = [s for s in load_calibration_samples() if str(s.get("project_id")) != project_id]
    all_samples.extend(samples)
    save_calibration_samples(all_samples)


def _build_feedback_records_for_project(
    project_id: str,
    *,
    include_guardrail_blocked: bool = False,
) -> List[Dict[str, object]]:
    projects = load_projects()
    project = next((p for p in projects if str(p.get("id")) == project_id), None)
    if project is None:
        return []
    project_score_scale = _resolve_project_score_scale_max(project)
    submissions = [s for s in load_submissions() if str(s.get("project_id")) == project_id]
    submissions_by_id: Dict[str, Dict[str, object]] = {str(s.get("id")): s for s in submissions}

    feedback_records: List[Dict[str, object]] = []
    ground_truth_rows = _list_project_ground_truth_records(
        project_id,
        include_guardrail_blocked=include_guardrail_blocked,
    )
    for row in ground_truth_rows:
        if not isinstance(row, dict):
            continue
        if _learning_quality_gate_is_blocked(row):
            continue
        judge_scores = row.get("judge_scores")
        if not isinstance(judge_scores, list) or len(judge_scores) not in (5, 7):
            continue
        source_submission_id = str(row.get("source_submission_id") or "").strip()
        sub = submissions_by_id.get(source_submission_id) if source_submission_id else None
        if sub is None:
            gt_text = str(row.get("shigong_text") or "").strip()
            if gt_text:
                sub = next(
                    (
                        s
                        for s in submissions
                        if str(s.get("text") or "").strip() == gt_text and _submission_is_scored(s)
                    ),
                    None,
                )
        if sub is None:
            continue

        report = sub.get("report") if isinstance(sub.get("report"), dict) else {}
        pred_raw = _to_float_or_none(report.get("pred_total_score"))
        if pred_raw is None:
            pred_raw = _to_float_or_none(report.get("rule_total_score"))
        if pred_raw is None:
            pred_raw = _to_float_or_none(report.get("total_score"))
        if pred_raw is None:
            pred_raw = _to_float_or_none(sub.get("total_score"))
        if pred_raw is None:
            continue

        predicted_total_100 = _convert_score_to_100(float(pred_raw), project_score_scale)
        if predicted_total_100 is None:
            continue

        row_scale = _normalize_score_scale_max(
            row.get("score_scale_max"),
            default=project_score_scale,
        )
        tags_by_judge = row.get("qualitative_tags_by_judge")
        judge_feedbacks: List[Dict[str, object]] = []
        for idx, score_raw in enumerate(judge_scores):
            score_value = _to_float_or_none(score_raw)
            if score_value is None:
                score_value = 0.0
            score_100 = _convert_score_to_100(score_value, row_scale)
            if score_100 is None:
                score_100 = 0.0
            tags: List[str] = []
            if isinstance(tags_by_judge, list) and idx < len(tags_by_judge):
                candidate = tags_by_judge[idx]
                if isinstance(candidate, list):
                    tags = [str(x).strip() for x in candidate if str(x).strip()]
            judge_feedbacks.append(
                {
                    "judge_index": idx + 1,
                    "score": round(float(score_100), 4),
                    "qualitative_tags": tags,
                }
            )

        normalized_row = _ground_truth_record_for_learning(
            row,
            default_score_scale_max=project_score_scale,
        )
        feedback_records.append(
            {
                "id": str(row.get("id") or ""),
                "project_id": project_id,
                "submission_id": str(sub.get("id") or ""),
                "predicted_total_score": round(float(predicted_total_100), 4),
                "final_total_score": round(float(normalized_row.get("final_score", 0.0)), 4),
                "judge_feedbacks": judge_feedbacks,
                "created_at": str(row.get("created_at") or _now_iso()),
            }
        )
    return feedback_records


def _auto_update_from_delta_cases(project_id: str) -> Dict[str, object]:
    projects = load_projects()
    project = next((p for p in projects if str(p.get("id")) == project_id), None)
    if project is None:
        return {"updated": False, "reason": "project_not_found"}

    delta_cases = [d for d in load_delta_cases() if str(d.get("project_id")) == project_id]
    if len(delta_cases) < 2:
        return {
            "updated": False,
            "reason": "insufficient_delta_cases",
            "sample_count": len(delta_cases),
        }

    dim_stats: Dict[str, Dict[str, float]] = {
        dim_id: {"sum": 0.0, "count": 0.0} for dim_id in DIMENSION_IDS
    }
    for case in delta_cases:
        dim_errors = case.get("dim_errors") or {}
        if not isinstance(dim_errors, dict):
            continue
        for dim_id, raw_err in dim_errors.items():
            did = _normalize_dimension_id(str(dim_id))
            try:
                err = float(raw_err)
            except Exception:
                continue
            dim_stats[did]["sum"] += err
            dim_stats[did]["count"] += 1.0

    candidates: List[Dict[str, object]] = []
    for dim_id in DIMENSION_IDS:
        count = int(dim_stats[dim_id]["count"])
        if count < 2:
            continue
        mean_error = dim_stats[dim_id]["sum"] / float(count)
        if abs(mean_error) < 0.8:
            continue
        candidates.append(
            {
                "dim_id": dim_id,
                "count": count,
                "mean_error": round(mean_error, 3),
                "abs_mean_error": abs(mean_error),
                "step": -1 if mean_error > 0 else 1,
            }
        )

    if not candidates:
        return {
            "updated": False,
            "reason": "no_adjustable_dimensions",
            "sample_count": len(delta_cases),
        }

    candidates.sort(key=lambda x: float(x.get("abs_mean_error") or 0.0), reverse=True)
    top_dims = candidates[:4]

    profiles = load_expert_profiles()
    profile, created = _ensure_project_expert_profile(project, profiles)
    if created:
        save_expert_profiles(profiles)
        save_projects(projects)

    weights_raw = _coerce_weights_raw(dict(profile.get("weights_raw") or _default_weights_raw()))
    new_weights_raw = dict(weights_raw)
    changed_dims: List[Dict[str, object]] = []
    for item in top_dims:
        dim_id = str(item.get("dim_id"))
        step = int(item.get("step") or 0)
        before = int(new_weights_raw.get(dim_id, 5))
        after = max(0, min(10, before + step))
        if after == before:
            continue
        new_weights_raw[dim_id] = after
        changed_dims.append(
            {
                "dim_id": dim_id,
                "before": before,
                "after": after,
                "mean_error": item.get("mean_error"),
                "count": item.get("count"),
            }
        )

    if not changed_dims:
        return {"updated": False, "reason": "weights_unchanged", "sample_count": len(delta_cases)}

    auto_name = (
        f"{project.get('name', '项目')}_auto_feedback_{datetime.now().strftime('%Y%m%d_%H%M%S')}"
    )
    new_profile = _new_expert_profile(auto_name, new_weights_raw)
    profiles.append(new_profile)
    save_expert_profiles(profiles)

    return {
        "updated": True,
        "sample_count": len(delta_cases),
        "changed_dims": changed_dims,
        "new_profile_id": new_profile["id"],
        "project_profile_mutated": False,
        "strategy": "delta_case_fallback",
        "new_weights_norm": dict(new_profile.get("weights_norm") or {}),
        "new_dimension_multipliers": _weights_norm_to_dimension_multipliers(
            dict(new_profile.get("weights_norm") or {})
        ),
    }


def _auto_update_project_weights_from_delta_cases(project_id: str) -> Dict[str, object]:
    """
    优先使用「总分+标签」定向反演（模块一/二）；
    若反馈样本不足再回退到 DELTA_CASE 规则。
    """
    projects = load_projects()
    project = next((p for p in projects if str(p.get("id")) == project_id), None)
    if project is None:
        return {"updated": False, "reason": "project_not_found"}

    profiles = load_expert_profiles()
    profile, created = _ensure_project_expert_profile(project, profiles)
    if created:
        save_expert_profiles(profiles)
        save_projects(projects)

    feedback_records = _build_feedback_records_for_project(project_id)
    if feedback_records:
        current_weights_norm = dict(profile.get("weights_norm") or {})
        calibrated = calibrate_weights(
            current_weights_norm,
            feedback_records,
            half_life_days=30.0,
            lr_tag=0.08,
            lr_global=0.004,
            ridge_lambda=0.06,
            min_weight=0.005,
        )
        new_weights_norm = dict(calibrated.get("weights_norm") or {})
        if new_weights_norm:
            new_weights_raw = _weights_raw_from_norm(new_weights_norm)
            auto_name = f"{project.get('name', '项目')}_tag_guided_{datetime.now().strftime('%Y%m%d_%H%M%S')}"
            new_profile = _new_expert_profile(auto_name, new_weights_raw)
            # 保留算法输出的精确归一化权重，避免反推整数造成信息损失
            new_profile["weights_norm"] = {
                dim_id: float(new_weights_norm.get(dim_id, 1.0 / len(DIMENSION_IDS)))
                for dim_id in DIMENSION_IDS
            }
            profiles.append(new_profile)
            save_expert_profiles(profiles)

            return {
                "updated": True,
                "strategy": "tag_guided_calibration",
                "sample_count": len(feedback_records),
                "new_profile_id": new_profile["id"],
                "project_profile_mutated": False,
                "calibration_stats": calibrated.get("stats") or {},
                "new_weights_norm": dict(new_profile.get("weights_norm") or {}),
                "new_dimension_multipliers": _weights_norm_to_dimension_multipliers(
                    dict(new_profile.get("weights_norm") or {})
                ),
            }

    # 回退：历史 DELTA_CASE 方案
    return _auto_update_from_delta_cases(project_id)


def _sync_feedback_weights_to_evolution(
    project_id: str,
    weight_update: Dict[str, object],
) -> Dict[str, object]:
    if not bool(weight_update.get("updated")):
        return {"synced": False, "reason": "weight_not_updated"}
    multipliers = weight_update.get("new_dimension_multipliers") or {}
    if not isinstance(multipliers, dict) or not multipliers:
        return {"synced": False, "reason": "missing_multipliers"}
    reports = load_evolution_reports()
    evo = reports.get(project_id) or {}
    scoring_evolution = (
        evo.get("scoring_evolution") if isinstance(evo.get("scoring_evolution"), dict) else {}
    )
    scoring_evolution = dict(scoring_evolution or {})
    scoring_evolution["dimension_multipliers"] = {
        dim_id: float(multipliers.get(dim_id, 1.0)) for dim_id in DIMENSION_IDS
    }
    scoring_evolution.setdefault("rationale", {})
    scoring_evolution["updated_by_feedback"] = True
    scoring_evolution["updated_by_feedback_at"] = _now_iso()
    candidate_profile_id = str(weight_update.get("new_profile_id") or "").strip()
    if candidate_profile_id:
        scoring_evolution["candidate_profile_id"] = candidate_profile_id
    scoring_evolution["project_expert_profile_read_only"] = True
    evo["scoring_evolution"] = scoring_evolution
    evo.setdefault("project_id", project_id)
    evo.setdefault("sample_count", 0)
    evo["updated_at"] = _now_iso()
    reports[project_id] = evo
    save_evolution_reports(reports)
    return {
        "synced": True,
        "dimension_multipliers_count": len(scoring_evolution.get("dimension_multipliers") or {}),
        "candidate_profile_id": candidate_profile_id or None,
        "project_profile_mutated": False,
    }


def _refresh_evolution_report_from_ground_truth(
    project_id: str,
    *,
    include_guardrail_blocked: bool = False,
) -> Dict[str, object]:
    projects = load_projects()
    project = next((p for p in projects if str(p.get("id")) == project_id), None)
    if project is None:
        return {"refreshed": False, "reason": "project_not_found"}
    project_score_scale = _resolve_project_score_scale_max(project)
    records_raw = _list_project_ground_truth_records(
        project_id,
        include_guardrail_blocked=include_guardrail_blocked,
    )
    records = [
        _ground_truth_record_for_learning(
            r if isinstance(r, dict) else {},
            default_score_scale_max=project_score_scale,
        )
        for r in records_raw
    ]
    ctx_data = load_project_context().get(project_id) or {}
    project_context = str(ctx_data.get("text") or "").strip()
    materials_text = _merge_materials_text(project_id)
    if materials_text:
        project_context = (
            (project_context + "\n\n" + materials_text) if project_context else materials_text
        )

    report = build_evolution_report(project_id, records, project_context)
    material_knowledge_profile = _build_material_knowledge_profile(project_id)
    report["material_learning_summary"] = {
        "dimension_coverage_rate": float(
            _to_float_or_none(
                ((material_knowledge_profile.get("summary") or {}).get("dimension_coverage_rate"))
                if isinstance(material_knowledge_profile, dict)
                else None
            )
            or 0.0
        ),
        "low_coverage_dimensions": int(
            _to_float_or_none(
                ((material_knowledge_profile.get("summary") or {}).get("low_coverage_dimensions"))
                if isinstance(material_knowledge_profile, dict)
                else None
            )
            or 0
        ),
        "structured_signal_total": int(
            _to_float_or_none(
                ((material_knowledge_profile.get("summary") or {}).get("structured_signal_total"))
                if isinstance(material_knowledge_profile, dict)
                else None
            )
            or 0
        ),
        "available_types": [
            str(row.get("material_type"))
            for row in (material_knowledge_profile.get("by_type") or [])[:8]
            if isinstance(row, dict) and str(row.get("material_type") or "").strip()
        ]
        if isinstance(material_knowledge_profile, dict)
        else [],
    }
    report["feature_confidence_summary"] = _build_feature_confidence_summary(
        project_id,
        material_knowledge_profile=material_knowledge_profile,
    )
    report["few_shot_examples"] = _build_project_few_shot_prompt_examples(project_id, limit=6)
    reports = load_evolution_reports()
    prev = reports.get(project_id) or {}
    # 自动闭环刷新时仅更新规则进化结果与编制指导；保留已有 LLM 增强来源标记。
    if isinstance(prev.get("enhanced_by"), str):
        report["enhanced_by"] = prev.get("enhanced_by")
    if isinstance(prev.get("calibrator_runtime_governance"), dict):
        report["calibrator_runtime_governance"] = dict(
            prev.get("calibrator_runtime_governance") or {}
        )
    reports[project_id] = report
    save_evolution_reports(reports)
    return {
        "refreshed": True,
        "sample_count": int(report.get("sample_count", 0) or 0),
    }


def _persist_calibrator_runtime_governance(
    project_id: str,
    governance: Optional[Dict[str, object]],
) -> Dict[str, object]:
    payload = dict(governance or {})
    if not payload:
        return {}
    payload["recorded_at"] = _now_iso()
    reports = load_evolution_reports()
    report = dict(reports.get(project_id) or {})
    report["project_id"] = project_id
    report["calibrator_runtime_governance"] = payload
    reports[project_id] = report
    save_evolution_reports(reports)
    return payload


