def _summarize_feature_rows_for_governance(rows: object) -> Dict[str, object]:
    typed_rows = [row for row in (rows if isinstance(rows, list) else []) if isinstance(row, dict)]
    active_rows = [row for row in typed_rows if bool(row.get("active", True))]
    high_conf_rows = [
        row
        for row in active_rows
        if float(_to_float_or_none(row.get("confidence_score")) or 0.0) >= 0.7
    ]
    dim_counter: Dict[str, int] = {}
    for row in active_rows:
        dim_id = (
            _normalize_dimension_id(row.get("dimension_id"))
            or str(row.get("dimension_id") or "").strip()
        )
        if not dim_id:
            continue
        dim_counter[dim_id] = dim_counter.get(dim_id, 0) + 1
    top_dimensions = [
        {"dimension_id": dim_id, "feature_count": count}
        for dim_id, count in sorted(dim_counter.items(), key=lambda item: (-item[1], item[0]))[:4]
    ]
    return {
        "summary_type": "high_score_features",
        "primary_count": len(typed_rows),
        "active_count": len(active_rows),
        "high_confidence_count": len(high_conf_rows),
        "dimension_count": len(dim_counter),
        "top_dimensions": top_dimensions,
    }


def _summarize_versioned_artifact_payload(
    artifact: str,
    payload: object,
    *,
    project_id: str,
) -> Dict[str, object]:
    if artifact == "high_score_features":
        return _summarize_feature_rows_for_governance(payload)
    if artifact == "calibration_models":
        rows = [
            row for row in (payload if isinstance(payload, list) else []) if isinstance(row, dict)
        ]
        latest = max(
            rows,
            key=lambda row: str(row.get("updated_at") or row.get("created_at") or ""),
            default={},
        )
        latest_auto_review = _calibrator_auto_review_state(latest)
        return {
            "summary_type": "calibration_models",
            "primary_count": len(rows),
            "latest_calibrator_version": str(latest.get("calibrator_version") or ""),
            "latest_model_type": str(latest.get("model_type") or ""),
            "gate_passed_count": sum(1 for row in rows if bool(row.get("gate_passed"))),
            "latest_bootstrap_small_sample": _calibrator_bootstrap_small_sample(latest),
            "latest_deployment_mode": _calibrator_deployment_mode(latest),
            "latest_auto_review_action": str(latest_auto_review.get("action") or ""),
            "latest_auto_review_passed": latest_auto_review.get("passed"),
        }
    if artifact == "expert_profiles":
        rows = [
            row for row in (payload if isinstance(payload, list) else []) if isinstance(row, dict)
        ]
        latest = max(
            rows,
            key=lambda row: str(row.get("updated_at") or row.get("created_at") or ""),
            default={},
        )
        return {
            "summary_type": "expert_profiles",
            "primary_count": len(rows),
            "read_only_count": sum(1 for row in rows if bool(row.get("read_only"))),
            "latest_profile_id": str(latest.get("id") or ""),
            "latest_profile_name": str(latest.get("name") or ""),
        }
    if artifact == "evolution_reports":
        rows = payload if isinstance(payload, dict) else {}
        project_payload = rows.get(project_id) if isinstance(rows.get(project_id), dict) else {}
        return {
            "summary_type": "evolution_reports",
            "primary_count": len(rows),
            "project_present": bool(project_payload),
            "project_high_score_logic_count": len(project_payload.get("high_score_logic") or []),
            "project_writing_guidance_count": len(project_payload.get("writing_guidance") or []),
            "project_updated_at": str(
                project_payload.get("updated_at") or project_payload.get("created_at") or ""
            ),
        }
    if isinstance(payload, list):
        return {"summary_type": "list", "primary_count": len(payload)}
    if isinstance(payload, dict):
        return {"summary_type": "dict", "primary_count": len(payload)}
    return {"summary_type": type(payload).__name__, "primary_count": 0}


def _artifact_payload_fingerprint(payload: object) -> str:
    try:
        return json.dumps(payload, ensure_ascii=False, sort_keys=True, separators=(",", ":"))
    except TypeError:
        return repr(payload)


def _artifact_summary_delta(
    current_summary: Dict[str, object],
    latest_summary: Dict[str, object],
) -> Dict[str, object]:
    delta: Dict[str, object] = {}
    for key, current_value in current_summary.items():
        latest_value = latest_summary.get(key)
        if not isinstance(current_value, (int, float)) or not isinstance(
            latest_value, (int, float)
        ):
            continue
        diff = float(current_value) - float(latest_value)
        delta[key] = (
            int(diff)
            if isinstance(current_value, int) and isinstance(latest_value, int)
            else round(diff, 4)
        )
    return delta


def _governance_artifact_specs() -> Dict[str, Dict[str, object]]:
    return {
        "high_score_features": {
            "path": HIGH_SCORE_FEATURES_PATH,
            "loader": load_high_score_features,
            "default_payload": [],
        },
        "evolution_reports": {
            "path": EVOLUTION_REPORTS_PATH,
            "loader": load_evolution_reports,
            "default_payload": {},
        },
        "calibration_models": {
            "path": CALIBRATION_MODELS_PATH,
            "loader": load_calibration_models,
            "default_payload": [],
        },
        "expert_profiles": {
            "path": EXPERT_PROFILES_PATH,
            "loader": load_expert_profiles,
            "default_payload": [],
        },
    }


def _resolve_governance_artifact_spec(artifact: str) -> Dict[str, object]:
    key = str(artifact or "").strip()
    spec = _governance_artifact_specs().get(key)
    if not isinstance(spec, dict):
        raise HTTPException(status_code=404, detail="历史版本配置不存在")
    return spec


def _load_latest_valid_governance_snapshot(path: Path, default_payload: object) -> object:
    for item in list_json_versions(path):
        version_id = str(item.get("version_id") or "").strip()
        if not version_id:
            continue
        try:
            return load_json_version(path, version_id, copy.deepcopy(default_payload))
        except StorageDataError:
            continue
    return copy.deepcopy(default_payload)


def _load_governance_artifact_payload(
    artifact: str,
    *,
    artifact_payload_overrides: Optional[Dict[str, object]] = None,
) -> object:
    if isinstance(artifact_payload_overrides, dict) and artifact in artifact_payload_overrides:
        return copy.deepcopy(artifact_payload_overrides.get(artifact))
    spec = _resolve_governance_artifact_spec(artifact)
    loader = spec.get("loader")
    if not callable(loader):
        raise HTTPException(status_code=500, detail="治理产物加载器不可用")
    default_payload = copy.deepcopy(spec.get("default_payload"))
    try:
        return loader()
    except StorageDataError as exc:
        path = spec.get("path")
        recovered_payload = (
            _load_latest_valid_governance_snapshot(path, default_payload)
            if isinstance(path, Path)
            else default_payload
        )
        logger.warning(
            "governance_artifact_storage_fallback artifact=%s path=%s code=%s detail=%s",
            artifact,
            getattr(exc, "path", path),
            getattr(exc, "code", ""),
            getattr(exc, "detail", str(exc)),
        )
        return recovered_payload


def _select_calibrator_model_from_rows(
    project: Dict[str, object],
    rows: List[Dict[str, object]],
) -> Optional[Dict[str, object]]:
    models = sorted(rows, key=lambda x: str(x.get("created_at", "")), reverse=True)
    if not models:
        return None
    project_id = str(project.get("id") or "")
    locked_version = str(project.get("calibrator_version_locked") or "")

    def _scope_project_id(model: Dict[str, object]) -> str:
        return str(((model.get("train_filter") or {}).get("project_id") or "")).strip()

    def _compatible(model: Dict[str, object]) -> bool:
        return _scope_project_id(model) == project_id

    if locked_version:
        for model in models:
            if str(model.get("calibrator_version") or "") == locked_version:
                return model if _compatible(model) else None
        return None

    for model in models:
        if bool(model.get("deployed")) and _compatible(model):
            return model
    return _build_five_scale_global_prior_calibrator(
        project
    ) or _build_hundred_scale_global_prior_calibrator(project)


def _resolve_project_scoring_context_for_governance(
    project_id: str,
    project: Dict[str, object],
    *,
    artifact_payload_overrides: Optional[Dict[str, object]] = None,
) -> tuple[Dict[str, float], Optional[Dict[str, object]], str]:
    profiles = _load_governance_artifact_payload(
        "expert_profiles",
        artifact_payload_overrides=artifact_payload_overrides,
    )
    profile = None
    if project.get("expert_profile_id"):
        for item in profiles if isinstance(profiles, list) else []:
            if isinstance(item, dict) and item.get("id") == project.get("expert_profile_id"):
                profile = item
                break

    evo_reports = _load_governance_artifact_payload(
        "evolution_reports",
        artifact_payload_overrides=artifact_payload_overrides,
    )
    project_evo = evo_reports.get(project_id) if isinstance(evo_reports, dict) else {}
    evo_status = _evaluate_evolution_weight_status(project_id, project=project, evo=project_evo)
    if bool(evo_status.get("usable")):
        return dict(evo_status.get("dimension_multipliers") or {}), None, "evolution"
    if profile and isinstance(profile.get("weights_norm"), dict):
        multipliers = _weights_norm_to_dimension_multipliers(profile.get("weights_norm", {}))
        return multipliers, profile, "expert_profile"
    if bool(evo_status.get("stored")):
        return {}, None, "evolution_stored_inactive"
    for learning_profile in load_learning_profiles():
        if learning_profile.get("project_id") == project_id:
            return (
                dict(learning_profile.get("dimension_multipliers") or {}),
                None,
                "learning_profile",
            )
    return {}, None, "default_uniform"


def _build_governance_artifact_impacts(
    project_id: str,
    *,
    artifact_payload_overrides: Optional[Dict[str, object]] = None,
) -> List[Dict[str, object]]:
    artifact_specs = _governance_artifact_specs()
    impacts: List[Dict[str, object]] = []
    for artifact, spec in artifact_specs.items():
        path = spec.get("path")
        default_payload = copy.deepcopy(spec.get("default_payload"))
        current_payload = _load_governance_artifact_payload(
            artifact,
            artifact_payload_overrides=artifact_payload_overrides,
        )
        current_summary = _summarize_versioned_artifact_payload(
            artifact, current_payload, project_id=project_id
        )
        versions = list_json_versions(path)
        latest_snapshot = versions[0] if versions else {}
        latest_summary: Dict[str, object] = {}
        latest_payload = None
        latest_version_id = str(latest_snapshot.get("version_id") or "")
        if latest_version_id:
            try:
                latest_payload = load_json_version(path, latest_version_id, default_payload)
                latest_summary = _summarize_versioned_artifact_payload(
                    artifact, latest_payload, project_id=project_id
                )
            except StorageDataError:
                latest_summary = {}
                latest_payload = None
        matches_latest_snapshot = (
            bool(latest_version_id)
            and latest_payload is not None
            and _artifact_payload_fingerprint(current_payload)
            == _artifact_payload_fingerprint(latest_payload)
        )
        impacts.append(
            {
                "artifact": artifact,
                "current_summary": current_summary,
                "latest_snapshot_version_id": latest_version_id or None,
                "latest_snapshot_created_at": str(latest_snapshot.get("created_at") or ""),
                "latest_snapshot_summary": latest_summary,
                "matches_latest_snapshot": matches_latest_snapshot,
                "changed_since_latest_snapshot": bool(latest_version_id)
                and not matches_latest_snapshot,
                "delta_vs_latest_snapshot": _artifact_summary_delta(
                    current_summary, latest_summary
                ),
            }
        )
    return impacts


def _resolve_qingtian_total_score_100(
    row: Dict[str, object],
    *,
    default_score_scale_max: int,
) -> Optional[float]:
    qt_total = _to_float_or_none(row.get("qt_total_score"))
    if qt_total is not None:
        return round(float(qt_total), 2)
    raw_payload = row.get("raw_payload") if isinstance(row.get("raw_payload"), dict) else {}
    if not raw_payload:
        return None
    normalized = _ground_truth_record_for_learning(
        {
            "final_score": raw_payload.get("final_score"),
            "final_score_raw": raw_payload.get("final_score_raw"),
            "final_score_100": raw_payload.get("final_score_100"),
            "score_scale_max": raw_payload.get("score_scale_max"),
            "judge_scores": raw_payload.get("judge_scores") or [],
        },
        default_score_scale_max=default_score_scale_max,
    )
    return _to_float_or_none(normalized.get("final_score"))


def _list_governance_comparable_submission_snapshots(
    project_id: str,
    project: Dict[str, object],
    *,
    ground_truth_rows_override: Optional[List[Dict[str, object]]] = None,
) -> List[Dict[str, object]]:
    project_score_scale = _resolve_project_score_scale_max(project)
    submissions = [s for s in load_submissions() if str(s.get("project_id") or "") == project_id]
    submissions_by_id = {
        str(item.get("id") or ""): item for item in submissions if str(item.get("id") or "").strip()
    }
    latest_reports = _latest_records_by_submission(
        [
            row
            for row in load_score_reports()
            if str(row.get("project_id") or "") == project_id
            and str(row.get("submission_id") or "") in submissions_by_id
        ]
    )
    blocked_gt_ids = {
        str(row.get("id") or "").strip()
        for row in _list_project_ground_truth_records(
            project_id,
            include_guardrail_blocked=True,
            rows_override=ground_truth_rows_override,
        )
        if _feedback_guardrail_blocks_training(row)
    }
    latest_qingtian = _latest_records_by_submission(
        [
            row
            for row in load_qingtian_results()
            if str(row.get("submission_id") or "") in latest_reports
            and str(row.get("submission_id") or "") in submissions_by_id
            and (
                str(((row.get("raw_payload") or {}).get("ground_truth_record_id") or "")).strip()
                not in blocked_gt_ids
            )
        ]
    )
    comparable_rows: List[Dict[str, object]] = []
    for submission_id, qt_row in latest_qingtian.items():
        submission = submissions_by_id.get(submission_id)
        stored_report = latest_reports.get(submission_id)
        if not isinstance(submission, dict) or not isinstance(stored_report, dict):
            continue
        qt_total_score = _resolve_qingtian_total_score_100(
            qt_row,
            default_score_scale_max=project_score_scale,
        )
        if qt_total_score is None:
            continue
        comparable_rows.append(
            {
                "submission_id": submission_id,
                "submission": submission,
                "stored_report": stored_report,
                "qingtian_row": qt_row,
                "qt_total_score": round(float(qt_total_score), 2),
            }
        )
    return sorted(
        comparable_rows,
        key=lambda item: (
            str(((item.get("qingtian_row") or {}).get("created_at") or "")),
            str(item.get("submission_id") or ""),
        ),
        reverse=True,
    )


def _build_governance_score_preview(
    project_id: str,
    project: Dict[str, object],
    artifact_impacts: List[Dict[str, object]],
    *,
    artifact_payload_overrides: Optional[Dict[str, object]] = None,
    ground_truth_rows_override: Optional[List[Dict[str, object]]] = None,
) -> Dict[str, object]:
    preview_limit = 8
    comparable_rows = _list_governance_comparable_submission_snapshots(
        project_id,
        project,
        ground_truth_rows_override=ground_truth_rows_override,
    )
    calibrator_rows = _load_governance_artifact_payload(
        "calibration_models",
        artifact_payload_overrides=artifact_payload_overrides,
    )
    calibrator = (
        _select_calibrator_model_from_rows(
            project,
            calibrator_rows if isinstance(calibrator_rows, list) else [],
        )
        or {}
    )
    calibrator_state = _summarize_project_calibrator_state(
        project,
        calibrator_rows if isinstance(calibrator_rows, list) else [],
    )
    current_calibrator_version = str(calibrator_state.get("current_calibrator_version") or "")
    requires_rule_rescore = any(
        bool(item.get("changed_since_latest_snapshot"))
        for item in artifact_impacts
        if str(item.get("artifact") or "")
        in {"high_score_features", "evolution_reports", "expert_profiles"}
    )
    calibrator_changed_since_latest_snapshot = any(
        bool(item.get("changed_since_latest_snapshot"))
        for item in artifact_impacts
        if str(item.get("artifact") or "") == "calibration_models"
    )

    all_rows: List[Dict[str, object]] = []
    for candidate in comparable_rows:
        submission_id = str(candidate.get("submission_id") or "")
        submission = candidate.get("submission")
        stored_report = candidate.get("stored_report")
        qt_row = candidate.get("qingtian_row")
        qt_total_score = _to_float_or_none(candidate.get("qt_total_score"))
        rule_total_score = (
            _to_float_or_none(stored_report.get("rule_total_score"))
            if isinstance(stored_report, dict)
            else None
        )
        if (
            qt_total_score is None
            or rule_total_score is None
            or not isinstance(submission, dict)
            or not isinstance(stored_report, dict)
            or not isinstance(qt_row, dict)
        ):
            continue
        preview_report = copy.deepcopy(stored_report)
        preview_submission = dict(submission)
        _apply_prediction_to_report_with_model(
            preview_report,
            submission_like=preview_submission,
            project=project,
            model_override=calibrator if calibrator else None,
        )
        stored_pred_total_score = _to_float_or_none(stored_report.get("pred_total_score"))
        stored_total_score = (
            stored_pred_total_score if stored_pred_total_score is not None else rule_total_score
        )
        preview_pred_total_score = _to_float_or_none(preview_report.get("pred_total_score"))
        preview_rule_total_score = _to_float_or_none(preview_report.get("rule_total_score"))
        preview_total_score = (
            preview_pred_total_score
            if preview_pred_total_score is not None
            else preview_rule_total_score
        )
        stored_signed_delta = (
            round(float(stored_total_score) - float(qt_total_score), 2)
            if stored_total_score is not None
            else None
        )
        preview_signed_delta = (
            round(float(preview_total_score) - float(qt_total_score), 2)
            if preview_total_score is not None
            else None
        )
        stored_abs_delta = (
            round(abs(float(stored_signed_delta)), 2) if stored_signed_delta is not None else None
        )
        preview_abs_delta = (
            round(abs(float(preview_signed_delta)), 2) if preview_signed_delta is not None else None
        )
        abs_delta_improvement = (
            round(float(stored_abs_delta) - float(preview_abs_delta), 2)
            if stored_abs_delta is not None and preview_abs_delta is not None
            else None
        )
        raw_payload = (
            qt_row.get("raw_payload") if isinstance(qt_row.get("raw_payload"), dict) else {}
        )
        all_rows.append(
            {
                "submission_id": submission_id,
                "filename": str(
                    submission.get("filename")
                    or raw_payload.get("source_submission_filename")
                    or ""
                ),
                "report_created_at": str(stored_report.get("created_at") or ""),
                "qingtian_created_at": str(qt_row.get("created_at") or ""),
                "source_ground_truth_id": str(raw_payload.get("ground_truth_record_id") or ""),
                "rule_total_score": round(float(rule_total_score), 2),
                "stored_pred_total_score": (
                    round(float(stored_pred_total_score), 2)
                    if stored_pred_total_score is not None
                    else None
                ),
                "stored_total_score": (
                    round(float(stored_total_score), 2) if stored_total_score is not None else None
                ),
                "preview_pred_total_score": (
                    round(float(preview_pred_total_score), 2)
                    if preview_pred_total_score is not None
                    else None
                ),
                "preview_total_score": (
                    round(float(preview_total_score), 2)
                    if preview_total_score is not None
                    else None
                ),
                "qt_total_score": round(float(qt_total_score), 2),
                "stored_signed_delta_100": stored_signed_delta,
                "preview_signed_delta_100": preview_signed_delta,
                "stored_abs_delta_100": stored_abs_delta,
                "preview_abs_delta_100": preview_abs_delta,
                "abs_delta_improvement": abs_delta_improvement,
            }
        )

    def _avg_numeric(key: str) -> Optional[float]:
        values = [float(row.get(key)) for row in all_rows if isinstance(row.get(key), (int, float))]
        if not values:
            return None
        return round(sum(values) / len(values), 2)

    improved_row_count = sum(
        1 for row in all_rows if (_to_float_or_none(row.get("abs_delta_improvement")) or 0.0) > 0.01
    )
    worsened_row_count = sum(
        1
        for row in all_rows
        if (_to_float_or_none(row.get("abs_delta_improvement")) or 0.0) < -0.01
    )

    return {
        "scope": "calibrator_only_preview",
        "matched_submission_count": len(all_rows),
        "preview_limit": preview_limit,
        "current_calibrator_version": current_calibrator_version or None,
        "current_calibrator_model_type": calibrator_state.get("current_calibrator_model_type"),
        "current_calibrator_source": calibrator_state.get("current_calibrator_source"),
        "current_calibrator_bootstrap_small_sample": bool(
            calibrator_state.get("current_calibrator_bootstrap_small_sample")
        ),
        "current_calibrator_deployment_mode": calibrator_state.get(
            "current_calibrator_deployment_mode"
        ),
        "current_calibrator_auto_review": calibrator_state.get("current_calibrator_auto_review")
        or {},
        "calibrator_changed_since_latest_snapshot": calibrator_changed_since_latest_snapshot,
        "requires_rule_rescore": requires_rule_rescore,
        "dimension_preview_supported": False,
        "avg_abs_delta_stored": _avg_numeric("stored_abs_delta_100"),
        "avg_abs_delta_preview": _avg_numeric("preview_abs_delta_100"),
        "avg_abs_delta_improvement": _avg_numeric("abs_delta_improvement"),
        "improved_row_count": improved_row_count,
        "worsened_row_count": worsened_row_count,
        "rows": all_rows[:preview_limit],
    }


def _extract_rule_dimension_score_map(report: Dict[str, object]) -> Dict[str, float]:
    scores: Dict[str, float] = {}
    rule_dim_scores = (
        report.get("rule_dim_scores") if isinstance(report.get("rule_dim_scores"), dict) else {}
    )
    for dim_id, payload in rule_dim_scores.items():
        normalized_dim_id = _normalize_dimension_id(str(dim_id))
        if not normalized_dim_id or not isinstance(payload, dict):
            continue
        score_value = _to_float_or_none(payload.get("dim_score"))
        if score_value is None:
            continue
        scores[normalized_dim_id] = round(float(score_value), 2)
    if scores:
        return scores
    dimension_scores = (
        report.get("dimension_scores") if isinstance(report.get("dimension_scores"), dict) else {}
    )
    for dim_id, payload in dimension_scores.items():
        normalized_dim_id = _normalize_dimension_id(str(dim_id))
        if not normalized_dim_id or not isinstance(payload, dict):
            continue
        score_value = _to_float_or_none(payload.get("score"))
        if score_value is None:
            continue
        scores[normalized_dim_id] = round(float(score_value), 2)
    return scores


def _build_submission_sandbox_report(
    *,
    project_id: str,
    project: Dict[str, object],
    submission: Dict[str, object],
    config: object,
    multipliers: Dict[str, float],
    profile_snapshot: Optional[Dict[str, object]],
    scoring_engine_version: str,
    anchors: Optional[List[Dict[str, object]]] = None,
    requirements: Optional[List[Dict[str, object]]] = None,
    material_quality_snapshot: Optional[Dict[str, object]] = None,
    material_knowledge_snapshot: Optional[Dict[str, object]] = None,
    calibrator_model_override: Optional[Dict[str, object]] = None,
) -> Dict[str, object]:
    text = str(submission.get("text") or "")
    if not text.strip():
        raise ValueError("施组文本为空，无法执行沙箱重评分。")
    report, _ = _score_submission_for_project(
        submission_id=str(submission.get("id") or "sandbox"),
        text=text,
        project_id=project_id,
        project=project,
        config=config,
        multipliers=multipliers,
        profile_snapshot=profile_snapshot,
        scoring_engine_version=scoring_engine_version,
        anchors=anchors,
        requirements=requirements,
        material_quality_snapshot=material_quality_snapshot,
        material_knowledge_snapshot=material_knowledge_snapshot,
    )
    if calibrator_model_override:
        submission_like = dict(submission)
        _apply_prediction_to_report_with_model(
            report,
            submission_like=submission_like,
            project=project,
            model_override=calibrator_model_override,
        )
    _apply_evolution_total_scale(project_id, report)
    return report


def _build_governance_sandbox_preview(
    project_id: str,
    project: Dict[str, object],
    *,
    artifact_payload_overrides: Optional[Dict[str, object]] = None,
    ground_truth_rows_override: Optional[List[Dict[str, object]]] = None,
) -> Dict[str, object]:
    preview_limit = 3
    comparable_rows = _list_governance_comparable_submission_snapshots(
        project_id,
        project,
        ground_truth_rows_override=ground_truth_rows_override,
    )
    scoring_engine_version = str(project.get("scoring_engine_version_locked") or "v1")
    engine_version = _determine_engine_version(project, scoring_engine_version)
    base_payload: Dict[str, object] = {
        "scope": "sandbox_rescore_preview",
        "matched_submission_count": len(comparable_rows),
        "preview_limit": preview_limit,
        "scoring_engine_version": scoring_engine_version,
        "engine_version": engine_version,
        "weights_source": "",
        "expert_profile_id": None,
        "constraints_ready": True,
        "constraints_warning": "",
        "executed_row_count": 0,
        "failed_row_count": 0,
        "dimension_preview_supported": True,
        "avg_abs_delta_stored": None,
        "avg_abs_delta_sandbox": None,
        "avg_abs_delta_improvement": None,
        "improved_row_count": 0,
        "worsened_row_count": 0,
        "rows": [],
        "errors": [],
    }
    if not comparable_rows:
        return base_payload

    multipliers, profile_snapshot, weights_source = _resolve_project_scoring_context_for_governance(
        project_id,
        project,
        artifact_payload_overrides=artifact_payload_overrides,
    )
    calibrator_rows = _load_governance_artifact_payload(
        "calibration_models",
        artifact_payload_overrides=artifact_payload_overrides,
    )
    calibrator_model = _select_calibrator_model_from_rows(
        project,
        calibrator_rows if isinstance(calibrator_rows, list) else [],
    )
    base_payload["weights_source"] = weights_source
    base_payload["expert_profile_id"] = (
        str(profile_snapshot.get("id") or "") if isinstance(profile_snapshot, dict) else None
    )
    config = load_config()
    material_knowledge_snapshot = _build_material_knowledge_profile(project_id)
    material_quality_snapshot = _build_material_quality_snapshot(project_id)
    anchors: Optional[List[Dict[str, object]]] = None
    requirements: Optional[List[Dict[str, object]]] = None
    if engine_version == "v2":
        stored_anchors = [
            a for a in load_project_anchors() if str(a.get("project_id") or "") == project_id
        ]
        stored_requirements = [
            r for r in load_project_requirements() if str(r.get("project_id") or "") == project_id
        ]
        if stored_anchors and stored_requirements:
            anchors = stored_anchors
            requirements = stored_requirements
        else:
            base_payload["constraints_ready"] = False
            base_payload[
                "constraints_warning"
            ] = "当前项目尚无已固化的目录锚点/要求约束，沙箱重评分暂不执行，以避免治理面板触发写入式重建。"
            return base_payload

    rows: List[Dict[str, object]] = []
    errors: List[Dict[str, object]] = []
    for candidate in comparable_rows[:preview_limit]:
        submission_id = str(candidate.get("submission_id") or "")
        submission = candidate.get("submission")
        stored_report = candidate.get("stored_report")
        qt_total_score = _to_float_or_none(candidate.get("qt_total_score"))
        if (
            not isinstance(submission, dict)
            or not isinstance(stored_report, dict)
            or qt_total_score is None
        ):
            continue
        try:
            sandbox_report = _build_submission_sandbox_report(
                project_id=project_id,
                project=project,
                submission=submission,
                config=config,
                multipliers=multipliers,
                profile_snapshot=profile_snapshot,
                scoring_engine_version=scoring_engine_version,
                anchors=anchors,
                requirements=requirements,
                material_quality_snapshot=material_quality_snapshot,
                material_knowledge_snapshot=material_knowledge_snapshot,
                calibrator_model_override=calibrator_model,
            )
        except Exception as exc:
            errors.append(
                {
                    "submission_id": submission_id,
                    "filename": str(submission.get("filename") or ""),
                    "message": f"{type(exc).__name__}: {exc}",
                }
            )
            continue

        stored_rule_total_score = _to_float_or_none(stored_report.get("rule_total_score"))
        stored_pred_total_score = _to_float_or_none(stored_report.get("pred_total_score"))
        stored_total_score = (
            stored_pred_total_score
            if stored_pred_total_score is not None
            else stored_rule_total_score
        )
        sandbox_rule_total_score = _to_float_or_none(sandbox_report.get("rule_total_score"))
        sandbox_pred_total_score = _to_float_or_none(sandbox_report.get("pred_total_score"))
        sandbox_total_score = (
            sandbox_pred_total_score
            if sandbox_pred_total_score is not None
            else sandbox_rule_total_score
        )
        stored_abs_delta = (
            round(abs(float(stored_total_score) - float(qt_total_score)), 2)
            if stored_total_score is not None
            else None
        )
        sandbox_abs_delta = (
            round(abs(float(sandbox_total_score) - float(qt_total_score)), 2)
            if sandbox_total_score is not None
            else None
        )
        abs_delta_improvement = (
            round(float(stored_abs_delta) - float(sandbox_abs_delta), 2)
            if stored_abs_delta is not None and sandbox_abs_delta is not None
            else None
        )
        stored_dim_scores = _extract_rule_dimension_score_map(stored_report)
        sandbox_dim_scores = _extract_rule_dimension_score_map(sandbox_report)
        changed_dimensions: List[Dict[str, object]] = []
        for dim_id in sorted(set(stored_dim_scores) | set(sandbox_dim_scores)):
            stored_dim_score = float(stored_dim_scores.get(dim_id, 0.0))
            sandbox_dim_score = float(sandbox_dim_scores.get(dim_id, 0.0))
            delta_value = round(sandbox_dim_score - stored_dim_score, 2)
            if abs(delta_value) <= 0.01:
                continue
            changed_dimensions.append(
                {
                    "dimension_id": dim_id,
                    "stored_rule_score": round(stored_dim_score, 2),
                    "sandbox_rule_score": round(sandbox_dim_score, 2),
                    "delta": delta_value,
                }
            )
        changed_dimensions.sort(
            key=lambda item: abs(float(item.get("delta") or 0.0)),
            reverse=True,
        )
        rows.append(
            {
                "submission_id": submission_id,
                "filename": str(submission.get("filename") or ""),
                "stored_total_score": (
                    round(float(stored_total_score), 2) if stored_total_score is not None else None
                ),
                "sandbox_total_score": (
                    round(float(sandbox_total_score), 2)
                    if sandbox_total_score is not None
                    else None
                ),
                "qt_total_score": round(float(qt_total_score), 2),
                "stored_abs_delta_100": stored_abs_delta,
                "sandbox_abs_delta_100": sandbox_abs_delta,
                "abs_delta_improvement": abs_delta_improvement,
                "changed_dimension_count": len(changed_dimensions),
                "top_changed_dimensions": changed_dimensions[:4],
                "sandbox_scoring_status": str(sandbox_report.get("scoring_status") or ""),
            }
        )

    def _avg_numeric(key: str) -> Optional[float]:
        values = [float(row.get(key)) for row in rows if isinstance(row.get(key), (int, float))]
        if not values:
            return None
        return round(sum(values) / len(values), 2)

    base_payload["executed_row_count"] = len(rows)
    base_payload["failed_row_count"] = len(errors)
    base_payload["avg_abs_delta_stored"] = _avg_numeric("stored_abs_delta_100")
    base_payload["avg_abs_delta_sandbox"] = _avg_numeric("sandbox_abs_delta_100")
    base_payload["avg_abs_delta_improvement"] = _avg_numeric("abs_delta_improvement")
    base_payload["improved_row_count"] = sum(
        1 for row in rows if (_to_float_or_none(row.get("abs_delta_improvement")) or 0.0) > 0.01
    )
    base_payload["worsened_row_count"] = sum(
        1 for row in rows if (_to_float_or_none(row.get("abs_delta_improvement")) or 0.0) < -0.01
    )
    base_payload["rows"] = rows
    base_payload["errors"] = errors[:6]
    return base_payload


