def _normalize_uploaded_filename(filename: str) -> str:
    raw = unicodedata.normalize("NFKC", str(filename or "")).replace("\u3000", " ").strip()
    base = Path(raw).name.strip()
    while base.endswith("."):
        base = base[:-1].rstrip()
    return base


def _infer_material_type_from_filename(filename: object) -> str:
    normalized = _normalize_uploaded_filename(str(filename or "")).lower()
    ext = Path(normalized).suffix.lower()
    name = normalized

    if ext in {".png", ".jpg", ".jpeg", ".webp", ".bmp", ".tif", ".tiff"}:
        if any(k in name for k in ("现场", "实景", "照片", "photo", "image", "img")):
            return "site_photo"
        return "drawing"
    if ext in {".dxf", ".dwg"}:
        return "drawing"
    if ext in {".xlsx", ".xls", ".xlsm", ".csv"}:
        return "boq"
    if any(k in name for k in ("清单", "boq", "bill_of_quantities", "工程量")):
        return "boq"
    if any(k in name for k in ("图纸", "总图", "平面", "立面", "剖面", "cad", "详图", "节点图")):
        return "drawing"
    if any(k in name for k in ("现场", "实景", "照片", "photo", "image", "img")):
        return "site_photo"
    return MATERIAL_TYPE_DEFAULT


def _normalize_material_type(material_type: object, *, filename: object = "") -> str:
    raw = str(material_type or "").strip().lower().replace("-", "_")
    if not raw:
        return _infer_material_type_from_filename(filename)
    normalized = MATERIAL_TYPE_ALIASES.get(raw, raw)
    if normalized in MATERIAL_TYPE_LABELS:
        return normalized
    return _infer_material_type_from_filename(filename)


def _parse_material_type_or_422(material_type: object, *, filename: object = "") -> str:
    raw = str(material_type or "").strip()
    if not raw:
        return _normalize_material_type("", filename=filename)
    normalized = _normalize_material_type(raw, filename=filename)
    raw_key = raw.lower().replace("-", "_")
    if raw_key in MATERIAL_TYPE_ALIASES or raw_key in MATERIAL_TYPE_LABELS:
        return normalized
    supported = "、".join(MATERIAL_TYPE_LABELS.keys())
    raise HTTPException(status_code=422, detail=f"material_type 不支持：{raw}（支持：{supported}）")


def _material_type_label(material_type: object, *, filename: object = "") -> str:
    return MATERIAL_TYPE_LABELS.get(
        _normalize_material_type(material_type, filename=filename), "项目资料"
    )


def _material_type_ext_hint(material_type: object, *, filename: object = "") -> str:
    normalized = _normalize_material_type(material_type, filename=filename)
    exts = MATERIAL_TYPE_ALLOWED_EXTS.get(normalized) or MATERIAL_ALLOWED_EXTS
    return "、".join(exts)


def _is_allowed_material_upload(filename: str, content_type: str, material_type: str) -> bool:
    normalized = _normalize_uploaded_filename(filename).lower()
    allowed_exts = MATERIAL_TYPE_ALLOWED_EXTS.get(material_type) or MATERIAL_ALLOWED_EXTS
    if normalized and any(normalized.endswith(ext) for ext in allowed_exts):
        return True
    ctype = str(content_type or "").lower().strip()
    allowed_tokens = (
        MATERIAL_TYPE_ALLOWED_MIME_TOKENS.get(material_type) or MATERIAL_ALLOWED_MIME_TOKENS
    )
    return any(token in ctype for token in allowed_tokens)


SUBMISSION_DUPLICATE_WINDOW_SECONDS = 15


def _parse_iso_datetime_utc(value: object) -> Optional[datetime]:
    raw = str(value or "").strip()
    if not raw:
        return None
    if raw.endswith("Z"):
        raw = raw[:-1] + "+00:00"
    try:
        dt = datetime.fromisoformat(raw)
    except ValueError:
        return None
    if dt.tzinfo is None:
        dt = dt.replace(tzinfo=timezone.utc)
    return dt.astimezone(timezone.utc)


def _find_recent_duplicate_submission(
    submissions: List[dict],
    *,
    project_id: str,
    filename: str,
    text: str,
    now_utc: datetime,
) -> Optional[dict]:
    normalized_filename = _normalize_uploaded_filename(filename)
    for submission in reversed(submissions):
        if submission.get("project_id") != project_id:
            continue
        if _normalize_uploaded_filename(submission.get("filename", "")) != normalized_filename:
            continue
        if str(submission.get("text") or "") != text:
            continue
        created_at = _parse_iso_datetime_utc(submission.get("created_at"))
        if created_at is None:
            continue
        age_seconds = (now_utc - created_at).total_seconds()
        if 0 <= age_seconds <= SUBMISSION_DUPLICATE_WINDOW_SECONDS:
            return submission
    return None


@router.post(
    "/projects/{project_id}/materials",
    tags=["项目管理"],
    responses={**RESPONSES_401, **RESPONSES_404},
)
async def upload_material(
    project_id: str,
    file: UploadFile = File(...),
    material_type: str = Form(MATERIAL_TYPE_DEFAULT),
    api_key: Optional[str] = Depends(verify_api_key),
    locale: str = Depends(get_locale),
) -> dict:
    """
    上传项目材料文件（支持按资料分类上传）。

    material_type:
    - tender_qa: 招标文件和答疑
    - boq: 清单
    - drawing: 图纸
    - site_photo: 现场照片

    **需要 API Key 认证**（未配置 API_KEYS 时无需）

    支持 Accept-Language header 进行多语言响应。
    """
    ensure_data_dirs()
    raw_name = file.filename or ""
    normalized_name = _normalize_uploaded_filename(raw_name)
    normalized_material_type = _parse_material_type_or_422(material_type, filename=normalized_name)
    if not normalized_name:
        raise HTTPException(status_code=422, detail="资料文件名为空，请重试或重命名后上传。")
    if not _is_allowed_material_upload(
        normalized_name, file.content_type or "", normalized_material_type
    ):
        raise HTTPException(
            status_code=422,
            detail=(
                _material_type_label(normalized_material_type)
                + "支持："
                + _material_type_ext_hint(normalized_material_type)
            ),
        )
    staged = await _stage_upload_file_to_temp_path(file, filename=normalized_name)
    try:
        if int(_to_float_or_none(staged.get("size_bytes")) or 0) <= 0:
            raise HTTPException(status_code=422, detail="资料文件为空，请重新选择文件。")
        return await _store_uploaded_material_from_local_path(
            project_id=project_id,
            source_path=Path(staged["path"]),
            normalized_name=normalized_name,
            normalized_material_type=normalized_material_type,
            locale=locale,
        )
    finally:
        _remove_temp_file(staged.get("path"))


@router.get(
    "/projects/{project_id}/materials",
    response_model=list[MaterialRecord],
    tags=["项目管理"],
    responses={**RESPONSES_404},
)
def list_materials(project_id: str, locale: str = Depends(get_locale)) -> list[MaterialRecord]:
    """获取指定项目下已上传的资料列表。"""
    ensure_data_dirs()
    projects = load_projects()
    if not any(p["id"] == project_id for p in projects):
        raise HTTPException(status_code=404, detail=t("api.project_not_found", locale=locale))
    materials = [m for m in load_materials() if m.get("project_id") == project_id]
    materials.sort(key=lambda x: str(x.get("created_at", "")), reverse=True)
    normalized_rows: List[dict] = []
    for material in materials:
        row, _ = _normalize_material_row_for_parse(dict(material))
        row["material_type"] = _normalize_material_type(
            row.get("material_type"), filename=row.get("filename")
        )
        normalized_rows.append(row)
    return [MaterialRecord(**m) for m in normalized_rows]


@router.get(
    "/projects/{project_id}/materials/{material_id}/detail",
    response_model=MaterialDetailResponse,
    tags=["项目管理"],
    responses={**RESPONSES_404},
)
def get_material_detail(
    project_id: str,
    material_id: str,
    locale: str = Depends(get_locale),
) -> MaterialDetailResponse:
    """返回单份项目资料的查看详情。"""
    ensure_data_dirs()
    projects = load_projects()
    if not any(p["id"] == project_id for p in projects):
        raise HTTPException(status_code=404, detail=t("api.project_not_found", locale=locale))
    materials = load_materials()
    found = next(
        (
            dict(item)
            for item in materials
            if str(item.get("id") or "").strip() == str(material_id or "").strip()
            and str(item.get("project_id") or "").strip() == str(project_id or "").strip()
        ),
        None,
    )
    if found is None:
        raise HTTPException(status_code=404, detail="资料记录不存在")
    normalized, _ = _normalize_material_row_for_parse(found)
    jobs = load_material_parse_jobs()
    _, latest_job = _find_latest_material_parse_job(
        jobs,
        str(normalized.get("id") or "").strip(),
    )
    normalized.update(
        _build_material_parse_runtime_details(
            normalized,
            active_job=latest_job,
        )
    )
    parsed_text = str(normalized.get("parsed_text") or "").strip()
    preview_text = parsed_text[:1800].strip()
    if parsed_text and len(parsed_text) > len(preview_text):
        preview_text = preview_text + "\n\n……（预览已截断）"
    return MaterialDetailResponse(
        id=str(normalized.get("id") or ""),
        project_id=str(normalized.get("project_id") or ""),
        material_type=str(normalized.get("material_type") or ""),
        filename=str(normalized.get("filename") or ""),
        created_at=str(normalized.get("created_at") or ""),
        parse_status=str(
            normalized.get("parse_effective_status") or normalized.get("parse_status") or ""
        )
        or None,
        parse_stage_label=str(normalized.get("parse_stage_label") or "").strip() or None,
        parse_note=str(normalized.get("parse_note") or "").strip() or None,
        parse_finished_at=str(
            normalized.get("parse_finished_at") or (latest_job or {}).get("finished_at") or ""
        ).strip()
        or None,
        parsed_chars=int(_to_float_or_none(normalized.get("parsed_chars")) or 0),
        parsed_text_preview=preview_text,
    )


@router.get(
    "/projects/{project_id}/materials/parse_status",
    response_model=MaterialParseStatusResponse,
    tags=["项目管理"],
    responses={**RESPONSES_404},
)
def get_material_parse_status(
    project_id: str,
    locale: str = Depends(get_locale),
) -> MaterialParseStatusResponse:
    ensure_data_dirs()
    projects = load_projects()
    if not any(p["id"] == project_id for p in projects):
        raise HTTPException(status_code=404, detail=t("api.project_not_found", locale=locale))
    project_cache_stats_before = _material_parse_project_cache_stats_snapshot(project_id)
    core_payload = _load_material_parse_status_core_payload(project_id)
    project_cache_request_delta = _build_material_parse_project_cache_request_delta(
        project_cache_stats_before,
        _material_parse_project_cache_stats_snapshot(project_id),
    )
    _record_material_parse_project_cache_request_delta(project_id, project_cache_request_delta)
    jobs = list(core_payload.get("jobs") or [])
    enriched_materials = list(core_payload.get("materials") or [])
    summary = dict(core_payload.get("summary") or {})
    summary.update(
        _build_material_parse_scheduler_summary(
            project_id,
            request_project_cache_delta=project_cache_request_delta,
        )
    )
    summary["worker_count"] = _material_parse_total_worker_count()
    summary["preview_express_reserved_worker_count"] = int(
        max(0, int(DEFAULT_MATERIAL_PARSE_PREVIEW_EXPRESS_RESERVED_WORKER_COUNT))
    )
    summary["preview_reserved_worker_count"] = int(
        max(0, int(DEFAULT_MATERIAL_PARSE_PREVIEW_RESERVED_WORKER_COUNT))
    )
    summary["alive_worker_count"] = _material_parse_worker_alive_count()
    overview = _build_material_parse_business_overview(summary)
    debug_info = _build_material_parse_debug_info(summary)
    return MaterialParseStatusResponse(
        project_id=project_id,
        overview=overview,
        summary=summary,
        debug_info=debug_info,
        jobs=[MaterialParseJobRecord(**job) for job in jobs],
        materials=[MaterialRecord(**row) for row in enriched_materials],
        generated_at=_now_iso(),
    )


@router.post(
    "/projects/{project_id}/materials/reparse",
    response_model=MaterialParseStatusResponse,
    tags=["项目管理"],
    responses={**RESPONSES_401, **RESPONSES_404},
)
def reparse_project_materials(
    project_id: str,
    api_key: Optional[str] = Depends(verify_api_key),
    locale: str = Depends(get_locale),
) -> MaterialParseStatusResponse:
    ensure_data_dirs()
    projects = load_projects()
    if not any(p["id"] == project_id for p in projects):
        raise HTTPException(status_code=404, detail=t("api.project_not_found", locale=locale))
    materials = load_materials()
    jobs = load_material_parse_jobs()
    changed = False
    for idx, row in enumerate(materials):
        if str(row.get("project_id") or "") != str(project_id):
            continue
        normalized, _ = _normalize_material_row_for_parse(dict(row))
        try:
            content_hash, size_bytes = _compute_material_content_hash_from_file(
                Path(str(normalized.get("path") or "").strip())
            )
        except OSError:
            parse_mode = "full"
            content_hash = str(normalized.get("content_hash") or "").strip() or None
        else:
            parse_mode = (
                "preview"
                if _material_should_use_preview_stage(
                    None,
                    str(normalized.get("filename") or ""),
                    material_type=normalized.get("material_type"),
                    size_bytes=size_bytes,
                )
                else "full"
            )
        jobs, job_id, _, _ = _requeue_material_parse_job(
            jobs,
            normalized,
            parse_mode=parse_mode,
        )
        normalized["job_id"] = job_id
        normalized["content_hash"] = content_hash
        normalized["parse_status"] = "queued"
        normalized["parse_backend"] = "queued"
        normalized["parse_phase"] = None
        normalized["parse_ready_for_gate"] = False
        normalized["parse_error_class"] = None
        normalized["parse_error_message"] = None
        normalized["parse_started_at"] = None
        normalized["parse_finished_at"] = None
        normalized["updated_at"] = _now_iso()
        materials[idx] = normalized
        changed = True
    if changed:
        save_materials(materials)
        save_material_parse_jobs(jobs)
        _notify_material_parse_workers()
        _invalidate_material_index_cache(project_id)
    return get_material_parse_status(project_id, locale)


