def _normalize_judge_scores_or_422(
    judge_scores: object,
    *,
    field_name: str = "judge_scores",
) -> List[float]:
    if not isinstance(judge_scores, list):
        raise HTTPException(status_code=422, detail=f"{field_name} 必须为数组。")
    judge_count = len(judge_scores)
    if judge_count not in (5, 7):
        raise HTTPException(status_code=422, detail=f"{field_name} 必须为 5 或 7 个评委得分。")
    normalized: List[float] = []
    for idx, value in enumerate(judge_scores, start=1):
        try:
            normalized.append(float(value))
        except Exception as exc:
            raise HTTPException(
                status_code=422,
                detail=f"{field_name}[{idx}] 不是有效数字：{exc}",
            )
    return normalized


def _normalize_judge_weights_or_422(
    judge_weights: object,
    *,
    expected_count: int,
) -> Optional[List[float]]:
    if judge_weights is None:
        return None
    if not isinstance(judge_weights, list):
        raise HTTPException(status_code=422, detail="judge_weights 必须为数组。")
    if len(judge_weights) != expected_count:
        raise HTTPException(
            status_code=422,
            detail=f"judge_weights 长度需与 judge_scores 一致（当前应为 {expected_count}）。",
        )
    normalized: List[float] = []
    for idx, value in enumerate(judge_weights, start=1):
        try:
            normalized.append(float(value))
        except Exception as exc:
            raise HTTPException(
                status_code=422,
                detail=f"judge_weights[{idx}] 不是有效数字：{exc}",
            )
    return normalized


def _normalize_qualitative_tags_or_422(
    tags_by_judge: object,
    *,
    expected_count: int,
) -> Optional[List[List[str]]]:
    if tags_by_judge is None:
        return None
    if not isinstance(tags_by_judge, list):
        raise HTTPException(status_code=422, detail="qualitative_tags_by_judge 必须为数组。")
    if len(tags_by_judge) != expected_count:
        raise HTTPException(
            status_code=422,
            detail=f"qualitative_tags_by_judge 长度需与 judge_scores 一致（当前应为 {expected_count}）。",
        )
    normalized: List[List[str]] = []
    for idx, tags in enumerate(tags_by_judge, start=1):
        if tags is None:
            normalized.append([])
            continue
        if not isinstance(tags, list):
            raise HTTPException(
                status_code=422,
                detail=f"qualitative_tags_by_judge[{idx}] 必须为字符串数组。",
            )
        clean_tags = [str(x).strip() for x in tags if str(x).strip()]
        normalized.append(clean_tags)
    return normalized


def _parse_judge_scores_form(judge_scores: str) -> List[float]:
    try:
        scores = json.loads(judge_scores)
    except Exception as e:
        raise HTTPException(status_code=422, detail=f"评委得分格式错误：{e}")
    return _normalize_judge_scores_or_422(scores)


def _assert_valid_final_score(final_score: float, *, score_scale_max: int = 100) -> None:
    scale = _normalize_score_scale_max(score_scale_max, default=100)
    if not (0 <= float(final_score) <= float(scale)):
        raise HTTPException(status_code=422, detail=f"最终得分应在 0～{scale} 之间。")


def _ground_truth_record_for_learning(
    record: Dict[str, object],
    *,
    default_score_scale_max: int,
) -> Dict[str, object]:
    score_scale_max = _normalize_score_scale_max(
        record.get("score_scale_max"),
        default=default_score_scale_max,
    )
    final_raw = _to_float_or_none(record.get("final_score_raw"))
    if final_raw is None:
        final_raw = _to_float_or_none(record.get("final_score"))
    if final_raw is None:
        final_raw = 0.0
    final_100 = _to_float_or_none(record.get("final_score_100"))
    if final_100 is None:
        final_100 = _convert_score_to_100(final_raw, score_scale_max)
    final_100 = float(final_100 if final_100 is not None else 0.0)
    judge_scores = record.get("judge_scores") or []
    judge_count = len(judge_scores) if isinstance(judge_scores, list) else 0
    normalized = dict(record)
    normalized["score_scale_max"] = score_scale_max
    normalized["final_score_raw"] = round(float(final_raw), 2)
    normalized["final_score_100"] = round(final_100, 2)
    normalized["final_score"] = round(final_100, 2)
    normalized["judge_count"] = judge_count
    return normalized


def _new_ground_truth_record(
    project_id: str,
    shigong_text: str,
    judge_scores: List[float],
    final_score: float,
    source: str,
    score_scale_max: int,
    judge_weights: Optional[List[float]] = None,
    qualitative_tags_by_judge: Optional[List[List[str]]] = None,
) -> Dict[str, object]:
    score_scale = _normalize_score_scale_max(score_scale_max, default=100)
    normalized_judge_scores = _normalize_judge_scores_or_422(judge_scores)
    normalized_judge_weights = _normalize_judge_weights_or_422(
        judge_weights,
        expected_count=len(normalized_judge_scores),
    )
    normalized_tags = _normalize_qualitative_tags_or_422(
        qualitative_tags_by_judge,
        expected_count=len(normalized_judge_scores),
    )
    final_raw = float(final_score)
    final_100 = _convert_score_to_100(final_raw, score_scale)
    final_100 = float(final_100 if final_100 is not None else 0.0)
    return {
        "id": str(uuid4()),
        "project_id": project_id,
        "shigong_text": shigong_text,
        "judge_scores": normalized_judge_scores,
        "judge_count": len(normalized_judge_scores),
        "score_scale_max": score_scale,
        "final_score": round(final_raw, 2),
        "final_score_raw": round(final_raw, 2),
        "final_score_100": round(final_100, 2),
        "judge_weights": normalized_judge_weights,
        "qualitative_tags_by_judge": normalized_tags,
        "source": source,
        "created_at": datetime.now(timezone.utc).isoformat(),
    }


def _persist_ground_truth_record_fields(
    project_id: str,
    record_id: str,
    *,
    updates: Dict[str, object],
) -> Dict[str, object]:
    records = load_ground_truth()
    now_iso = _now_iso()
    updated_row = None
    for idx, row in enumerate(records):
        if str(row.get("project_id") or "") != str(project_id):
            continue
        if str(row.get("id") or "") != str(record_id):
            continue
        merged = dict(row)
        merged.update(updates)
        merged["updated_at"] = now_iso
        records[idx] = merged
        updated_row = merged
        break
    if updated_row is None:
        raise HTTPException(status_code=404, detail="真实评标记录不存在")
    save_ground_truth(records)
    return updated_row


def _apply_feedback_guardrail_review(
    record: Dict[str, object],
    *,
    action: str,
    note: str,
) -> Dict[str, object]:
    guardrail = _extract_feedback_guardrail(record)
    if not bool(guardrail.get("threshold_blocked")) and action != "reset":
        raise HTTPException(status_code=422, detail="该样本未触发极端偏差拦截，无需人工放行/拒绝。")
    if action == "approve":
        review_status = "approved"
    elif action == "reject":
        review_status = "rejected"
    elif action == "reset":
        review_status = "pending" if bool(guardrail.get("threshold_blocked")) else "not_required"
    else:
        raise HTTPException(status_code=422, detail="action 仅支持 approve、reject、reset")
    reviewed_at = _now_iso() if review_status != "pending" else None
    guardrail["manual_review"] = {
        "status": review_status,
        "note": note or None,
        "reviewed_at": reviewed_at,
    }
    return _normalize_feedback_guardrail_state(guardrail)


def _apply_few_shot_review(
    record: Dict[str, object],
    *,
    action: str,
    note: str,
) -> Dict[str, object]:
    distillation = _normalize_few_shot_distillation_state(record.get("few_shot_distillation"))
    if int(_to_float_or_none(distillation.get("captured")) or 0) <= 0 and action != "reset":
        raise HTTPException(status_code=422, detail="该样本尚未捕获 few-shot 特征，无需采纳治理。")
    if action == "adopt":
        review_status = "adopted"
    elif action == "ignore":
        review_status = "ignored"
    elif action == "reset":
        review_status = (
            "pending"
            if int(_to_float_or_none(distillation.get("captured")) or 0) > 0
            else "not_required"
        )
    else:
        raise HTTPException(status_code=422, detail="action 仅支持 adopt、ignore、reset")
    reviewed_at = _now_iso() if review_status != "pending" else None
    distillation["manual_review"] = {
        "status": review_status,
        "note": note or None,
        "reviewed_at": reviewed_at,
    }
    return _normalize_few_shot_distillation_state(distillation)


def _sync_feature_governance_review(
    *,
    feature_ids: List[str],
    review_status: str,
    reviewed_at: Optional[str] = None,
) -> Dict[str, object]:
    target_ids = {
        str(item or "").strip() for item in (feature_ids or []) if str(item or "").strip()
    }
    if not target_ids:
        return {"updated": 0, "feature_ids": []}
    normalized_status = str(review_status or "").strip().lower()
    if normalized_status not in {"pending", "adopted", "ignored", "auto_adopted"}:
        normalized_status = "pending"
    now = reviewed_at or _now_iso()
    features = load_feature_kb()
    updated = 0
    for feature in features:
        feature_id = str(getattr(feature, "feature_id", "") or "").strip()
        if feature_id not in target_ids:
            continue
        feature.governance_status = normalized_status
        feature.updated_at = now
        if normalized_status == "ignored":
            feature.active = False
            feature.retired_at = now
        else:
            feature.active = True
            feature.retired_at = None
        updated += 1
    if updated:
        save_feature_kb(features)
    return {
        "updated": updated,
        "feature_ids": sorted(target_ids),
        "review_status": normalized_status,
    }


def _build_project_few_shot_prompt_examples(
    project_id: str,
    *,
    limit: int = 6,
) -> List[Dict[str, object]]:
    rows = [
        row for row in load_ground_truth() if str(row.get("project_id") or "") == str(project_id)
    ]
    eligible_feature_ids: set[str] = set()
    for row in rows:
        distillation = _normalize_few_shot_distillation_state(row.get("few_shot_distillation"))
        if str(distillation.get("manual_review_status") or "").strip().lower() != "adopted":
            continue
        for feature_id in distillation.get("feature_ids") or []:
            fid = str(feature_id or "").strip()
            if fid:
                eligible_feature_ids.add(fid)
    if not eligible_feature_ids:
        return []
    candidates: List[Dict[str, object]] = []
    for feature in load_feature_kb():
        feature_id = str(getattr(feature, "feature_id", "") or "").strip()
        if feature_id not in eligible_feature_ids or not bool(getattr(feature, "active", False)):
            continue
        governance_status = str(getattr(feature, "governance_status", "") or "").strip().lower()
        if governance_status not in {"adopted", "auto_adopted"}:
            continue
        dim_id = str(getattr(feature, "dimension_id", "") or "").strip().upper()
        candidates.append(
            {
                "feature_id": feature_id,
                "dimension_id": dim_id,
                "dimension_name": str((DIMENSIONS.get(dim_id) or {}).get("name") or dim_id).strip(),
                "logic_skeleton": list(getattr(feature, "logic_skeleton", []) or [])[:3],
                "source_highlights": list(getattr(feature, "source_highlights", []) or [])[:3],
                "governance_status": governance_status,
                "confidence_score": round(
                    float(_to_float_or_none(getattr(feature, "confidence_score", None)) or 0.0), 4
                ),
                "usage_count": int(_to_float_or_none(getattr(feature, "usage_count", None)) or 0),
            }
        )
    candidates.sort(
        key=lambda item: (
            float(_to_float_or_none(item.get("confidence_score")) or 0.0),
            int(_to_float_or_none(item.get("usage_count")) or 0),
        ),
        reverse=True,
    )
    return candidates[: max(1, int(limit or 6))]


