@router.post(
    "/projects/{project_id}/ground_truth/from_file",
    response_model=GroundTruthRecord,
    tags=["自我学习与进化"],
    responses={**RESPONSES_401, **RESPONSES_404, **RESPONSES_422},
)
async def add_ground_truth_from_file(
    project_id: str,
    file: UploadFile = File(...),
    judge_scores: str = Form(..., description="5或7个评委得分，JSON 数组如 [1,2,3,4,5]"),
    final_score: float = Form(...),
    source: str = Form("青天大模型"),
    api_key: Optional[str] = Depends(verify_api_key),
    locale: str = Depends(get_locale),
) -> GroundTruthRecord:
    """
    通过上传施组文件录入一条真实评标。后端解析文件为文本后保存。
    用于界面简洁录入：选文件 + 评委分 + 最终分即可。
    """
    ensure_data_dirs()
    normalized_filename = (
        _normalize_uploaded_filename(file.filename or "") or "ground_truth_upload.bin"
    )
    staged = await _stage_upload_file_to_temp_path(file, filename=normalized_filename)
    try:
        if int(_to_float_or_none(staged.get("size_bytes")) or 0) <= 0:
            raise HTTPException(status_code=422, detail="施组文件为空，请重新选择文件。")
        record = await run_in_threadpool(
            _build_ground_truth_record_from_uploaded_path,
            project_id,
            filename=normalized_filename,
            file_path=Path(staged["path"]),
            judge_scores_form=judge_scores,
            final_score=final_score,
            source=source,
            locale=locale,
        )
    finally:
        _remove_temp_file(staged.get("path"))
    records = load_ground_truth()
    records.append(record)
    save_ground_truth(records)
    record = _finalize_ground_truth_learning_record(
        project_id,
        record,
        locale=locale,
        trigger="ground_truth_add",
    )
    return GroundTruthRecord(**record)


@router.post(
    "/projects/{project_id}/ground_truth/from_files",
    response_model=GroundTruthBatchResponse,
    tags=["自我学习与进化"],
    responses={**RESPONSES_401, **RESPONSES_404, **RESPONSES_422},
)
async def add_ground_truth_from_files(
    project_id: str,
    files: List[UploadFile] = File(...),
    judge_scores: str = Form(..., description="5或7个评委得分，JSON 数组如 [1,2,3,4,5]"),
    final_score: float = Form(...),
    source: str = Form("青天大模型"),
    api_key: Optional[str] = Depends(verify_api_key),
    locale: str = Depends(get_locale),
) -> GroundTruthBatchResponse:
    """
    通过上传多个施组文件批量录入真实评标。后端将逐个解析并保存。
    """
    ensure_data_dirs()
    staged_uploads: List[tuple[str, Path]] = []
    try:
        for uploaded in files:
            normalized_filename = _normalize_uploaded_filename(uploaded.filename or "") or "unknown"
            staged = await _stage_upload_file_to_temp_path(uploaded, filename=normalized_filename)
            staged_uploads.append((normalized_filename, Path(staged["path"])))
        items, success_records = await run_in_threadpool(
            _build_ground_truth_batch_items_from_uploaded_paths,
            project_id,
            uploads=staged_uploads,
            judge_scores_form=judge_scores,
            final_score=final_score,
            source=source,
            locale=locale,
        )
    finally:
        for _, staged_path in staged_uploads:
            _remove_temp_file(staged_path)

    if success_records:
        records = load_ground_truth()
        records.extend(success_records)
        save_ground_truth(records)
        items = _finalize_ground_truth_batch_learning_records(
            project_id,
            items,
            locale=locale,
            trigger="ground_truth_batch_add",
        )

    success_count = sum(1 for item in items if item.get("ok"))
    failed_count = len(items) - success_count
    return GroundTruthBatchResponse(
        project_id=project_id,
        total_files=len(items),
        success_count=success_count,
        failed_count=failed_count,
        items=items,
    )


