@router.delete(
    "/projects/{project_id}/ground_truth/{record_id}",
    status_code=204,
    tags=["自我学习与进化"],
    responses={**RESPONSES_401, **RESPONSES_404},
)
def delete_ground_truth(
    project_id: str,
    record_id: str,
    api_key: Optional[str] = Depends(verify_api_key),
    locale: str = Depends(get_locale),
) -> None:
    """删除指定项目下的一条真实评标记录。"""
    ensure_data_dirs()
    projects = load_projects()
    if not any(p["id"] == project_id for p in projects):
        raise HTTPException(status_code=404, detail=t("api.project_not_found", locale=locale))
    records = load_ground_truth()
    if not any(r.get("id") == record_id and r.get("project_id") == project_id for r in records):
        raise HTTPException(status_code=404, detail="真实评标记录不存在")
    removed = next(
        (r for r in records if r.get("id") == record_id and r.get("project_id") == project_id),
        None,
    )
    records = [
        r for r in records if not (r.get("id") == record_id and r.get("project_id") == project_id)
    ]
    save_ground_truth(records)
    if removed is not None:
        gt_id = str(removed.get("id") or "")
        qtrs = load_qingtian_results()
        linked_submission_ids = {
            str(q.get("submission_id") or "")
            for q in qtrs
            if str((q.get("raw_payload") or {}).get("ground_truth_record_id") or "") == gt_id
        }
        qtrs = [
            q
            for q in qtrs
            if str((q.get("raw_payload") or {}).get("ground_truth_record_id") or "") != gt_id
        ]
        save_qingtian_results(qtrs)

        submissions = load_submissions()
        auto_submission_ids = {
            str(s.get("id") or "")
            for s in submissions
            if str(s.get("source_ground_truth_id") or "") == gt_id
            and str(s.get("project_id")) == project_id
        }
        remove_submission_ids = linked_submission_ids.union(auto_submission_ids)
        if remove_submission_ids:
            submissions = [
                s for s in submissions if str(s.get("id") or "") not in remove_submission_ids
            ]
            save_submissions(submissions)
            reports = load_score_reports()
            reports = [
                r for r in reports if str(r.get("submission_id") or "") not in remove_submission_ids
            ]
            save_score_reports(reports)
            units = _load_evidence_units_safe()
            units = [
                u for u in units if str(u.get("submission_id") or "") not in remove_submission_ids
            ]
            save_evidence_units(units)
        _refresh_project_reflection_objects(project_id)


@router.post(
    "/projects/{project_id}/evolve",
    response_model=EvolutionReport,
    tags=["自我学习与进化"],
    responses={**RESPONSES_401, **RESPONSES_404},
)
def evolve_project(
    project_id: str,
    confirm_extreme_sample: bool = Query(False, description="人工确认纳入极端偏差样本"),
    api_key: Optional[str] = Depends(verify_ops_api_key),
    locale: str = Depends(get_locale),
) -> EvolutionReport:
    """
    根据已录入的真实评标结果进行学习，生成高分逻辑与编制指导并保存。
    执行后可通过「编制指导」接口或页面查看。
    """
    ensure_data_dirs()
    projects = load_projects()
    project = next((p for p in projects if p["id"] == project_id), None)
    if project is None:
        raise HTTPException(status_code=404, detail=t("api.project_not_found", locale=locale))
    evolution_readiness = _build_evolution_readiness(project_id, project)
    if not bool(evolution_readiness.get("ready")):
        issue_texts = [
            str(item).strip()
            for item in (evolution_readiness.get("issues") or [])
            if str(item).strip()
        ]
        raise HTTPException(
            status_code=422,
            detail=issue_texts[0] if issue_texts else "请先完成施组评分后再执行学习与校准。",
        )
    _refresh_project_ground_truth_learning_records(project_id)
    blocked_guardrails = _collect_blocked_ground_truth_guardrails(project_id)
    before_manual_confirmation_payload = _build_manual_confirmation_audit_payload(
        project_id,
        project,
        blocked_guardrails_override=blocked_guardrails,
    )
    if blocked_guardrails and not bool(confirm_extreme_sample):
        raise HTTPException(
            status_code=409,
            detail=_build_manual_confirmation_detail(
                project_id,
                action_label="学习进化",
            ),
        )
    project_score_scale = _resolve_project_score_scale_max(project)
    records_raw = _list_project_ground_truth_records(
        project_id,
        include_guardrail_blocked=bool(confirm_extreme_sample),
    )
    records = [
        _ground_truth_record_for_learning(
            r if isinstance(r, dict) else {},
            default_score_scale_max=project_score_scale,
        )
        for r in records_raw
    ]
    ctx_data = load_project_context().get(project_id) or {}
    project_context = (ctx_data.get("text") or "").strip()
    materials_text = _merge_materials_text(project_id)
    if materials_text:
        project_context = (
            (project_context + "\n\n" + materials_text) if project_context else materials_text
        )
    report = build_evolution_report(project_id, records, project_context)
    report["few_shot_examples"] = _build_project_few_shot_prompt_examples(project_id, limit=6)
    enhanced = enhance_evolution_report_with_llm(project_id, report, records, project_context)
    if enhanced is not None:
        report["high_score_logic"] = enhanced.get("high_score_logic", report["high_score_logic"])
        report["writing_guidance"] = enhanced.get("writing_guidance", report["writing_guidance"])
        report["sample_count"] = enhanced.get("sample_count", report["sample_count"])
        report["updated_at"] = enhanced.get("updated_at", report["updated_at"])
        report["enhanced_by"] = enhanced.get(
            "enhanced_by"
        )  # 可追溯：真实 provider（当前为 openai | gemini）
        report["enhancement_provider_chain"] = list(
            enhanced.get("enhancement_provider_chain") or []
        )
        report["enhancement_fallback_used"] = bool(enhanced.get("enhancement_fallback_used"))
        report["enhancement_attempts"] = int(enhanced.get("enhancement_attempts") or 0)
        report["enhancement_applied"] = bool(enhanced.get("enhancement_applied", True))
        report["enhancement_governed"] = bool(enhanced.get("enhancement_governed", False))
        report["enhancement_governance_notes"] = list(
            enhanced.get("enhancement_governance_notes") or []
        )
        report["enhancement_review_provider"] = enhanced.get("enhancement_review_provider")
        report["enhancement_review_status"] = str(
            enhanced.get("enhancement_review_status") or "not_run"
        )
        review_similarity = enhanced.get("enhancement_review_similarity")
        report["enhancement_review_similarity"] = (
            float(review_similarity) if review_similarity is not None else None
        )
        report["enhancement_review_notes"] = list(enhanced.get("enhancement_review_notes") or [])
        # 保留规则版产出的 scoring_evolution、compilation_instructions（LLM 仅增强文字部分）
    reports = load_evolution_reports()
    governance_payload = _build_feedback_governance_report(project_id, project)
    report["manual_confirmation_audit"] = _build_manual_confirmation_audit(
        project_id,
        project,
        action_label="学习进化",
        confirm_extreme_sample_used=bool(confirm_extreme_sample),
        governance_payload=governance_payload,
        before_payload=before_manual_confirmation_payload,
    )
    reports[project_id] = report
    save_evolution_reports(reports)
    return EvolutionReport(**report)


@router.get(
    "/projects/{project_id}/writing_guidance",
    response_model=WritingGuidance,
    tags=["自我学习与进化"],
    responses=RESPONSES_404,
)
def get_writing_guidance(
    project_id: str,
    locale: str = Depends(get_locale),
) -> WritingGuidance:
    """
    获取编制指导。若已执行过「学习进化」则返回学习结果；否则返回引导说明。
    """
    ensure_data_dirs()
    projects = load_projects()
    if not any(p["id"] == project_id for p in projects):
        raise HTTPException(status_code=404, detail=t("api.project_not_found", locale=locale))
    reports = load_evolution_reports()
    data = reports.get(project_id)
    pending_feedback_payload = _build_pending_feedback_scoring_points(project_id)
    pending_feedback_summary = (
        pending_feedback_payload.get("summary")
        if isinstance(pending_feedback_payload.get("summary"), dict)
        else {}
    )
    pending_feedback_patch_bundle = (
        pending_feedback_payload.get("patch_bundle")
        if isinstance(pending_feedback_payload.get("patch_bundle"), dict)
        else {}
    )
    if data:
        return WritingGuidance(
            project_id=project_id,
            guidance=data.get("writing_guidance", []),
            high_score_logic=data.get("high_score_logic", []),
            pending_feedback_summary=pending_feedback_summary,
            pending_feedback_patch_bundle=pending_feedback_patch_bundle,
            sample_count=data.get("sample_count", 0),
            updated_at=data.get("updated_at"),
            enhancement_applied=bool(data.get("enhancement_applied", True)),
            enhancement_governed=bool(data.get("enhancement_governed", False)),
            enhancement_governance_notes=list(data.get("enhancement_governance_notes") or []),
            enhancement_review_provider=data.get("enhancement_review_provider"),
            enhancement_review_status=str(data.get("enhancement_review_status") or "not_run"),
            enhancement_review_similarity=(
                float(data.get("enhancement_review_similarity"))
                if data.get("enhancement_review_similarity") is not None
                else None
            ),
            enhancement_review_notes=list(data.get("enhancement_review_notes") or []),
        )
    return WritingGuidance(
        project_id=project_id,
        guidance=[
            "请先录入「真实评标结果」（施组+5/7评委得分+最终得分），再点击「学习进化」生成编制指导。"
        ],
        high_score_logic=[],
        pending_feedback_summary=pending_feedback_summary,
        pending_feedback_patch_bundle=pending_feedback_patch_bundle,
        sample_count=0,
        updated_at=None,
        enhancement_applied=False,
    )


def _render_writing_guidance_markdown(payload: Dict[str, object]) -> str:
    data = payload if isinstance(payload, dict) else {}
    pending_feedback_summary = (
        data.get("pending_feedback_summary")
        if isinstance(data.get("pending_feedback_summary"), dict)
        else {}
    )
    pending_feedback_patch_bundle = (
        data.get("pending_feedback_patch_bundle")
        if isinstance(data.get("pending_feedback_patch_bundle"), dict)
        else {}
    )
    lines = [
        "# 编制指导",
        "",
        f"- 项目ID：`{data.get('project_id') or '-'}`",
        f"- 已生效样本数：`{data.get('sample_count', 0)}`",
        f"- 更新时间：`{data.get('updated_at') or '-'}`",
        "",
    ]
    high_score_logic = data.get("high_score_logic") or []
    if isinstance(high_score_logic, list) and high_score_logic:
        lines.extend(["## 高分逻辑", ""])
        for item in high_score_logic:
            lines.append(f"- {item}")
        lines.append("")
    guidance = data.get("guidance") or []
    if isinstance(guidance, list) and guidance:
        lines.extend(["## 编制指导", ""])
        for item in guidance:
            lines.append(f"- {item}")
        lines.append("")
    if pending_feedback_summary or pending_feedback_patch_bundle:
        lines.extend(
            [
                "## 待确认反馈改写补丁包",
                "",
                f"- 待人工确认样本：`{pending_feedback_summary.get('pending_sample_count', 0)}`",
                f"- 待确认反馈点：`{pending_feedback_summary.get('pending_point_count', 0)}`",
                f"- 补丁小节数：`{pending_feedback_patch_bundle.get('section_count', 0)}`",
                "",
            ]
        )
        bundle_markdown = str(pending_feedback_patch_bundle.get("copy_markdown") or "").strip()
        if bundle_markdown:
            lines.append(bundle_markdown)
            lines.append("")
    notes = data.get("enhancement_governance_notes") or []
    if isinstance(notes, list) and notes:
        lines.extend(["## 进化治理备注", ""])
        for item in notes:
            lines.append(f"- {item}")
        lines.append("")
    return "\n".join(lines).strip()


def _render_pending_feedback_patch_bundle_markdown(payload: Dict[str, object]) -> str:
    data = payload if isinstance(payload, dict) else {}
    pending_feedback_summary = (
        data.get("pending_feedback_summary")
        if isinstance(data.get("pending_feedback_summary"), dict)
        else {}
    )
    pending_feedback_patch_bundle = (
        data.get("pending_feedback_patch_bundle")
        if isinstance(data.get("pending_feedback_patch_bundle"), dict)
        else {}
    )
    lines = [
        "# 待确认反馈改写补丁包",
        "",
        f"- 项目ID：`{data.get('project_id') or '-'}`",
        f"- 待人工确认样本：`{pending_feedback_summary.get('pending_sample_count', 0)}`",
        f"- 待确认反馈点：`{pending_feedback_summary.get('pending_point_count', 0)}`",
        f"- 补丁小节数：`{pending_feedback_patch_bundle.get('section_count', 0)}`",
        f"- 章节锚点插入：`{pending_feedback_patch_bundle.get('insert_after_anchor_count', 0)}`",
        f"- 关键词锚点插入：`{pending_feedback_patch_bundle.get('keyword_anchor_count', 0)}`",
        f"- 新增小节：`{pending_feedback_patch_bundle.get('append_new_section_count', 0)}`",
        "",
        "> 以下内容来自待人工确认样本整理出的项目级改写补丁，尚未正式进入评分主链。",
        "",
    ]
    bundle_markdown = str(pending_feedback_patch_bundle.get("copy_markdown") or "").strip()
    if bundle_markdown:
        lines.extend(["## 项目级补丁正文", "", bundle_markdown, ""])
    else:
        lines.extend(["> 当前暂无可导出的改写补丁。", ""])
    return "\n".join(lines).strip()


def _render_pending_feedback_patch_bundle_docx(payload: Dict[str, object]) -> bytes:
    if Document is None:
        raise RuntimeError("python-docx 不可用，无法导出改写补丁包 DOCX。")

    data = payload if isinstance(payload, dict) else {}
    pending_feedback_summary = (
        data.get("pending_feedback_summary")
        if isinstance(data.get("pending_feedback_summary"), dict)
        else {}
    )
    pending_feedback_patch_bundle = (
        data.get("pending_feedback_patch_bundle")
        if isinstance(data.get("pending_feedback_patch_bundle"), dict)
        else {}
    )
    sections = [
        item
        for item in (pending_feedback_patch_bundle.get("sections") or [])
        if isinstance(item, dict)
    ]

    doc = Document()
    doc.add_heading("待确认反馈改写补丁包", level=0)
    doc.add_paragraph(f"项目ID：{data.get('project_id') or '-'}")
    doc.add_paragraph(f"待人工确认样本：{pending_feedback_summary.get('pending_sample_count', 0)}")
    doc.add_paragraph(f"待确认反馈点：{pending_feedback_summary.get('pending_point_count', 0)}")
    doc.add_paragraph(f"补丁小节数：{pending_feedback_patch_bundle.get('section_count', 0)}")
    doc.add_paragraph(
        f"章节锚点插入：{pending_feedback_patch_bundle.get('insert_after_anchor_count', 0)}"
    )
    doc.add_paragraph(
        f"关键词锚点插入：{pending_feedback_patch_bundle.get('keyword_anchor_count', 0)}"
    )
    doc.add_paragraph(
        f"新增小节：{pending_feedback_patch_bundle.get('append_new_section_count', 0)}"
    )
    doc.add_paragraph(
        "说明：以下内容来自待人工确认样本整理出的项目级改写补丁，尚未正式进入评分主链。"
    )

    if sections:
        doc.add_heading("项目级补丁正文", level=1)
        for idx, section in enumerate(sections, start=1):
            title = str(section.get("section_title") or "").strip() or f"补丁 {idx}"
            doc.add_heading(f"{idx}. {title}", level=2)
            dimension_label = str(section.get("dimension_label") or "").strip()
            if dimension_label:
                doc.add_paragraph(f"维度：{dimension_label}")
            operation_label = str(section.get("operation_label") or "").strip()
            if operation_label:
                doc.add_paragraph(f"写入方式：{operation_label}")
            target = str(section.get("target") or "").strip()
            if target:
                doc.add_paragraph(f"写入位置：{target}")
            doc.add_paragraph("改写正文：")
            section_paragraphs = [
                str(item or "").strip()
                for item in (section.get("section_paragraphs") or [])
                if str(item or "").strip()
            ]
            if section_paragraphs:
                for paragraph in section_paragraphs:
                    doc.add_paragraph(paragraph)
            else:
                doc.add_paragraph("当前暂无可导出的改写正文。")
            copy_block = str(section.get("copy_block") or "").strip()
            if copy_block:
                doc.add_paragraph("可复制补丁：")
                for line in copy_block.splitlines():
                    text = str(line or "").strip()
                    if text:
                        doc.add_paragraph(text)
    else:
        doc.add_paragraph("当前暂无可导出的改写补丁。")

    buffer = io.BytesIO()
    doc.save(buffer)
    return buffer.getvalue()


