@app.get("/", tags=["系统状态"], include_in_schema=False)
@app.get("/developer/debug", tags=["系统状态"], include_in_schema=False)
def index(
    request: Request,
    create_ok: Optional[str] = Query(None),
    create_error: Optional[str] = Query(None),
    project_id: Optional[str] = Query(None),
    msg: Optional[str] = Query(None),
    msg_type: Optional[str] = Query(None),
) -> Response:
    ensure_data_dirs()
    developer_debug_mode = str(request.url.path or "").rstrip("/") == "/developer/debug"
    projects = load_projects()
    if not os.environ.get("PYTEST_CURRENT_TEST"):
        active_projects = [
            p
            for p in projects
            if str(p.get("id") or "") != "p1" and not str(p.get("name") or "").startswith("E2E_")
        ]
        if not active_projects:
            recovered = _recover_latest_orphan_project(projects)
            if recovered is not None:
                projects = load_projects()
    project_ids = [str(p.get("id", "")) for p in projects]
    if (not os.environ.get("PYTEST_CURRENT_TEST")) and project_id and project_id not in project_ids:
        recovered = _recover_missing_project_from_artifacts(project_id, projects)
        if recovered is not None:
            projects = load_projects()
            project_ids = [str(p.get("id", "")) for p in projects]
    picker_month_default = _default_project_picker_month_key(projects)
    picker_projects = _filter_projects_for_picker(projects, month_key=picker_month_default)
    picker_project_ids = [str(p.get("id", "")) for p in picker_projects]
    selected_project_id = ""
    if create_error and not project_id:
        selected_project_id = ""
    elif project_id and project_id in picker_project_ids:
        selected_project_id = project_id
    elif picker_project_ids:
        selected_project_id = picker_project_ids[-1]
    project_options = []
    project_search_options = []
    project_month_options = ['<option value="all">全部月份</option>']
    for month_key in _project_picker_month_choices(projects):
        selected_attr = " selected" if month_key == picker_month_default else ""
        project_month_options.append(
            f'<option value="{html_lib.escape(month_key)}"{selected_attr}>'
            f"{html_lib.escape(_project_picker_month_label(month_key))}</option>"
        )
    for p in picker_projects:
        pid_raw = str(p.get("id", ""))
        pid = html_lib.escape(pid_raw)
        pname = html_lib.escape(str(p.get("name", p.get("id", ""))))
        selected_attr = " selected" if pid_raw == selected_project_id else ""
        project_options.append(
            f'<option value="{pid}" data-project-name="{pname}"{selected_attr}>{pname}</option>'
        )
        project_search_options.append(f'<option value="{pname}"></option>')
    project_options_html = "".join(project_options)
